1	#!/usr/bin/env node
2	/**
3	 * Maintenance script — purge expired rows from time-bounded tables.
4	 *
5	 * Run on a schedule (e.g., daily via cron):
6	 *   node scripts/purge-expired-data.js
7	 *
8	 * Tables purged:
9	 *   - idempotency_keys:   rows past their expires_at
10	 *   - sessions:           rows past their absolute_expires_at
11	 *   - search_query_log:   rows older than RETENTION_DAYS
12	 *   - entity_view_history: rows older than HISTORY_RETENTION_DAYS
13	 *
14	 * Each purge is logged; the script exits 0 on success, 1 on error.
15	 */
16	
17	import knex from '../src/common/db/knex.js';
18	import config from '../src/config/env.js';
19	
20	const SEARCH_LOG_RETENTION_DAYS = 90;
21	const HISTORY_RETENTION_DAYS = config.personalization?.historyRetentionDays ?? 180;
22	
23	async function purge() {
24	  const results = {};
25	
26	  // ── Idempotency keys ──────────────────────────────────────────────────────
27	  results.idempotencyKeys = await knex('idempotency_keys')
28	    .where('expires_at', '<', knex.fn.now())
29	    .delete();
30	
31	  // ── Sessions ──────────────────────────────────────────────────────────────
32	  results.sessions = await knex('sessions')
33	    .where('absolute_expires_at', '<', knex.fn.now())
34	    .delete();
35	
36	  // ── Search query log ──────────────────────────────────────────────────────
37	  results.searchQueryLog = await knex('search_query_log')
38	    .whereRaw('created_at < NOW() - INTERVAL ? DAY', [SEARCH_LOG_RETENTION_DAYS])
39	    .delete();
40	
41	  // ── Entity view history ───────────────────────────────────────────────────
42	  results.entityViewHistory = await knex('entity_view_history')
43	    .whereRaw('viewed_at < NOW() - INTERVAL ? DAY', [HISTORY_RETENTION_DAYS])
44	    .delete();
45	
46	  return results;
47	}
48	
49	purge()
50	  .then((results) => {
51	    console.log('[purge] Completed:', JSON.stringify(results));
52	    process.exit(0);
53	  })
54	  .catch((err) => {
55	    console.error('[purge] Error:', err.message);
56	    process.exit(1);
57	  })
58	  .finally(() => knex.destroy());
59

1	import Router from '@koa/router';
2	import { requirePermission } from '../rbac/rbac.middleware.js';
3	import { validate } from '../../common/middleware/validate.middleware.js';
4	import { searchService } from './search.service.js';
5	import { savedQueriesService } from './saved-queries.service.js';
6	import { z } from 'zod';
7	
8	export const searchRouter = new Router({ prefix: '/search' });
9	
10	const searchQuerySchema = z.object({
11	  q: z.string().min(1).max(500),
12	  entityTypes: z.string().optional().transform((v) => v?.split(',').filter(Boolean)),
13	  page: z.coerce.number().int().min(1).default(1),
14	  pageSize: z.coerce.number().int().min(1).max(100).default(20),
15	});
16	
17	const savedQuerySchema = z.object({
18	  name: z.string().min(1).max(200),
19	  queryText: z.string().min(1).max(500),
20	  filters: z.object({ entityTypes: z.array(z.string()).optional() }).optional(),
21	  subscribed: z.boolean().default(false),
22	});
23	
24	// GET /v1/search?q=<query>
25	searchRouter.get(
26	  '/',
27	  requirePermission('search', 'query'),
28	  validate({ query: searchQuerySchema }),
29	  async (ctx) => {
30	    const { q, entityTypes, page, pageSize } = ctx.query;
31	    const result = await searchService.search(q, {
32	      entityTypes,
33	      page,
34	      pageSize,
35	      accountId: ctx.state.user?.id,
36	      requestId: ctx.state.requestId,
37	    });
38	    ctx.body = {
39	      data: result.rows,
40	      meta: {
41	        requestId: ctx.state.requestId,
42	        total: result.total,
43	        query: result.queryText,
44	        durationMs: result.durationMs,
45	        page,
46	        pageSize,
47	      },
48	    };
49	  },
50	);
51	
52	// GET /v1/search/suggest?q=<prefix>
53	searchRouter.get(
54	  '/suggest',
55	  requirePermission('search', 'query'),
56	  async (ctx) => {
57	    const prefix = String(ctx.query.q || '');
58	    const suggestions = await searchService.suggest(prefix);
59	    ctx.body = { data: suggestions, meta: { requestId: ctx.state.requestId } };
60	  },
61	);
62	
63	// ── Saved queries ─────────────────────────────────────────────────────────────
64	
65	// GET /v1/search/saved-queries
66	searchRouter.get(
67	  '/saved-queries',
68	  requirePermission('search', 'saved-query:manage'),
69	  async (ctx) => {
70	    const result = await savedQueriesService.list(ctx.state.user.id, ctx.query);
71	    ctx.body = {
72	      data: result.rows,
73	      meta: { requestId: ctx.state.requestId, total: result.total },
74	    };
75	  },
76	);
77	
78	// POST /v1/search/saved-queries
79	searchRouter.post(
80	  '/saved-queries',
81	  requirePermission('search', 'saved-query:manage'),
82	  validate({ body: savedQuerySchema }),
83	  async (ctx) => {
84	    const sq = await savedQueriesService.create({
85	      accountId: ctx.state.user.id,
86	      ...ctx.request.body,
87	    });
88	    ctx.status = 201;
89	    ctx.body = { data: sq, meta: { requestId: ctx.state.requestId } };
90	  },
91	);
92	
93	// PATCH /v1/search/saved-queries/:id
94	searchRouter.patch(
95	  '/saved-queries/:id',
96	  requirePermission('search', 'saved-query:manage'),
97	  async (ctx) => {
98	    const sq = await savedQueriesService.update(ctx.params.id, ctx.state.user.id, ctx.request.body);
99	    ctx.body = { data: sq, meta: { requestId: ctx.state.requestId } };
100	  },
101	);
102	
103	// DELETE /v1/search/saved-queries/:id
104	searchRouter.delete(
105	  '/saved-queries/:id',
106	  requirePermission('search', 'saved-query:manage'),
107	  async (ctx) => {
108	    await savedQueriesService.delete(ctx.params.id, ctx.state.user.id);
109	    ctx.status = 204;
110	  },
111	);
112	
113	// POST /v1/search/saved-queries/:id/run — execute a saved query
114	searchRouter.post(
115	  '/saved-queries/:id/run',
116	  requirePermission('search', 'saved-query:manage'),
117	  async (ctx) => {
118	    const result = await savedQueriesService.run(ctx.params.id, ctx.state.user.id);
119	    ctx.body = {
120	      data: result.rows,
121	      meta: { requestId: ctx.state.requestId, total: result.total, query: result.queryText },
122	    };
123	  },
124	);
125

1	import { withTransaction } from '../../common/db/transaction.js';
2	import { NotFoundError, ConflictError, AuthorizationError } from '../../common/errors/AppError.js';
3	import { searchService } from './search.service.js';
4	import knex from '../../common/db/knex.js';
5	
6	export const savedQueriesService = {
7	  async list(accountId, options = {}) {
8	    const page = Number(options.page) || 1;
9	    const pageSize = Math.min(Number(options.pageSize) || 20, 100);
10	    const q = knex('search_saved_queries')
11	      .where({ account_id: accountId })
12	      .orderBy('updated_at', 'desc');
13	    if (options.subscribed != null) q.where('subscribed', options.subscribed === 'true');
14	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
15	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
16	    return { rows, total };
17	  },
18	
19	  async create({ accountId, name, queryText, filters = {}, subscribed = false }) {
20	    try {
21	      const [sq] = await knex('search_saved_queries')
22	        .insert({ account_id: accountId, name, query_text: queryText, filters: JSON.stringify(filters), subscribed })
23	        .returning('*');
24	      return sq;
25	    } catch (err) {
26	      if (err.code === '23505') throw new ConflictError('A saved query with this name already exists');
27	      throw err;
28	    }
29	  },
30	
31	  async update(id, accountId, patch) {
32	    const sq = await knex('search_saved_queries').where({ id }).first();
33	    if (!sq) throw new NotFoundError('Saved query not found');
34	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
35	
36	    const allowed = ['name', 'query_text', 'filters', 'subscribed'];
37	    const update = { updated_at: new Date().toISOString() };
38	    for (const key of allowed) {
39	      if (patch[key] != null) update[key] = key === 'filters' ? JSON.stringify(patch[key]) : patch[key];
40	    }
41	    const [updated] = await knex('search_saved_queries').where({ id }).update(update).returning('*');
42	    return updated;
43	  },
44	
45	  async delete(id, accountId) {
46	    const sq = await knex('search_saved_queries').where({ id }).first();
47	    if (!sq) throw new NotFoundError('Saved query not found');
48	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
49	    await knex('search_saved_queries').where({ id }).delete();
50	  },
51	
52	  /**
53	   * Run a saved query and update last_run_at + last_result_count.
54	   */
55	  async run(id, accountId) {
56	    const sq = await knex('search_saved_queries').where({ id }).first();
57	    if (!sq) throw new NotFoundError('Saved query not found');
58	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
59	
60	    const result = await searchService.search(sq.query_text, {
61	      entityTypes: sq.filters?.entityTypes,
62	      accountId,
63	    });
64	
65	    await knex('search_saved_queries').where({ id }).update({
66	      last_run_at: new Date().toISOString(),
67	      last_result_count: result.total,
68	      updated_at: new Date().toISOString(),
69	    });
70	
71	    return result;
72	  },
73	};
74

1	import Router from '@koa/router';
2	import { accountService } from './account.service.js';
3	import { requirePermission } from '../rbac/rbac.middleware.js';
4	import { validate } from '../../common/middleware/validate.middleware.js';
5	import { z } from 'zod';
6	
7	export const accountsRouter = new Router({ prefix: '/accounts' });
8	
9	const createAccountSchema = z.object({
10	  username: z.string().min(3).max(100),
11	  password: z.string().min(12),
12	  email: z.string().email().optional(),
13	  displayName: z.string().max(200).optional(),
14	});
15	
16	// GET /v1/accounts/me — authenticated user's own profile
17	accountsRouter.get('/me', requirePermission('accounts', 'self:read'), async (ctx) => {
18	  const account = await accountService.getById(ctx.state.user.id);
19	  ctx.body = { data: account, meta: { requestId: ctx.state.requestId } };
20	});
21	
22	// GET /v1/accounts/:id — admin only
23	accountsRouter.get(
24	  '/:id',
25	  requirePermission('accounts', 'admin:manage'),
26	  async (ctx) => {
27	    const account = await accountService.getById(ctx.params.id);
28	    ctx.body = { data: account, meta: { requestId: ctx.state.requestId } };
29	  },
30	);
31	
32	// POST /v1/accounts — admin only
33	accountsRouter.post(
34	  '/',
35	  requirePermission('accounts', 'admin:manage'),
36	  validate({ body: createAccountSchema }),
37	  async (ctx) => {
38	    const account = await accountService.create(ctx.request.body);
39	    ctx.status = 201;
40	    ctx.body = { data: account, meta: { requestId: ctx.state.requestId } };
41	  },
42	);
43	
44	// PATCH /v1/accounts/:id/status — admin only
45	accountsRouter.patch(
46	  '/:id/status',
47	  requirePermission('accounts', 'admin:manage'),
48	  validate({
49	    body: z.object({ status: z.enum(['active', 'inactive', 'suspended']) }),
50	  }),
51	  async (ctx) => {
52	    const account = await accountService.updateStatus(
53	      ctx.params.id,
54	      ctx.request.body.status,
55	    );
56	    ctx.body = { data: account, meta: { requestId: ctx.state.requestId } };
57	  },
58	);
