7	export const accountService = {
8	  async getById(accountId) {
9	    const account = await knex('accounts')
10	      .where({ id: accountId })
11	      .first('id', 'username', 'status', 'password_last_rotated_at', 'created_at');
12	    if (!account) throw new NotFoundError('Account not found');
13	    return account;
