16	  async create({ username, password, email, displayName }) {
17	    passwordService.validateComplexity(password);
18	
19	    const existing = await knex('accounts').where({ username }).first('id');
20	    if (existing) throw new ConflictError('Username already taken');
21	
22	    const passwordHash = await passwordService.hash(password);
23	
24	    return withTransaction(async (trx) => {
25	      const [account] = await trx('accounts')
26	        .insert({
27	          username,
28	          password_hash: passwordHash,
29	          email_encrypted: email ? encrypt(email) : null,
30	          display_name_encrypted: displayName ? encrypt(displayName) : null,
31	        })
32	        .returning('id', 'username', 'status', 'created_at');
