1	import { createCipheriv, createDecipheriv, randomBytes } from 'crypto';
2	import config from '../../config/env.js';
3	
4	const ALGORITHM = 'aes-256-gcm';
5	const IV_BYTES = 12;   // 96-bit IV for GCM
6	const TAG_BYTES = 16;  // 128-bit authentication tag
7	
8	/**
9	 * Encrypts a UTF-8 string value using AES-256-GCM.
10	 * Returns a base64-encoded string in the format: iv:ciphertext:tag
11	 * Suitable for storing in a TEXT column.
12	 *
13	 * @param {string} plaintext
14	 * @returns {string}  Encrypted value
15	 */
16	export function encrypt(plaintext) {
17	  if (plaintext == null) return null;
18	  const key = Buffer.from(config.localEncryptionKey, 'hex');
19	  const iv = randomBytes(IV_BYTES);
20	  const cipher = createCipheriv(ALGORITHM, key, iv);
21	  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
22	  const tag = cipher.getAuthTag();
23	  // Format: base64(iv) : base64(ciphertext) : base64(tag)
24	  return [iv.toString('base64'), encrypted.toString('base64'), tag.toString('base64')].join(':');
25	}
26	
27	/**
28	 * Decrypts a value previously encrypted with encrypt().
29	 * @param {string} encryptedValue
30	 * @returns {string}  Plaintext
31	 */
32	export function decrypt(encryptedValue) {
33	  if (encryptedValue == null) return null;
34	  const key = Buffer.from(config.localEncryptionKey, 'hex');
35	  const [ivB64, dataB64, tagB64] = encryptedValue.split(':');
36	  const iv = Buffer.from(ivB64, 'base64');
37	  const data = Buffer.from(dataB64, 'base64');
38	  const tag = Buffer.from(tagB64, 'base64');
39	  const decipher = createDecipheriv(ALGORITHM, key, iv);
40	  decipher.setAuthTag(tag);
41	  return decipher.update(data, undefined, 'utf8') + decipher.final('utf8');
42	}
43	
44	/**
45	 * Returns a masked representation for use in audit views.
46	 * Shows first 2 and last 2 characters; middle is replaced with ***
47	 * @param {string} plaintext
48	 * @returns {string}
49	 */
50	export function maskField(plaintext) {
51	  if (!plaintext || plaintext.length <= 4) return '***';
52	  return `${plaintext.slice(0, 2)}***${plaintext.slice(-2)}`;
53	}
