1	import { requestFingerprint } from '../crypto/tokens.js';
2	import { idempotencyRepository } from './idempotency.repository.js';
3	import { ConflictError } from '../errors/AppError.js';
4	
5	// HTTP methods that require idempotency protection
6	const IDEMPOTENT_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
7	
8	/**
9	 * Idempotency-key middleware.
10	 *
11	 * For authenticated write requests (POST/PUT/PATCH/DELETE):
12	 *   - Missing Idempotency-Key header → 400 MISSING_IDEMPOTENCY_KEY
13	 *   - Key present, no prior record → execute handler, store response
14	 *   - Key present, matching fingerprint → return cached response (deduplication)
15	 *   - Key present, different fingerprint → 409 Conflict
16	 *
17	 * Unauthenticated write requests (e.g. POST /v1/auth/login) are exempt.
18	 */
19	export function idempotencyMiddleware() {
20	  return async function idempotency(ctx, next) {
21	    const idempotencyKey = ctx.get('Idempotency-Key');
22	
23	    // Skip non-write methods entirely
24	    if (!IDEMPOTENT_METHODS.has(ctx.method)) {
25	      await next();
26	      return;
27	    }
28	
29	    // Unauthenticated write requests (e.g. POST /v1/auth/login) bypass idempotency
30	    const accountId = ctx.state.user?.id;
31	    if (!accountId) {
32	      await next();
33	      return;
33	    }
34	
35	    // Authenticated write requests MUST supply an Idempotency-Key
36	    if (!idempotencyKey) {
37	      ctx.status = 400;
38	      ctx.body = {
39	        error: {
40	          code: 'MISSING_IDEMPOTENCY_KEY',
41	          message: 'Idempotency-Key header is required for authenticated write operations',
42	        },
43	        meta: { requestId: ctx.state.requestId },
44	      };
45	      return;
46	    }
47	
48	    const fingerprint = requestFingerprint(ctx.method, ctx.path, ctx.request.body || {});
49	
50	    // Check for existing record
51	    const existing = await idempotencyRepository.findByAccountAndKey(accountId, idempotencyKey);
52	
53	    if (existing) {
54	      if (existing.request_fingerprint !== fingerprint) {
55	        throw new ConflictError(
56	          'Idempotency key already used with a different request body',
57	        );
58	      }
59	      // Return cached response
60	      ctx.status = existing.response_status;
61	      ctx.body = typeof existing.response_body === 'string'
62	        ? JSON.parse(existing.response_body)
63	        : existing.response_body;
64	      return;
65	    }
66	
67	    // Execute the actual handler
68	    await next();
69	
70	    // Store response for future deduplication (only for successful responses)
71	    if (ctx.status >= 200 && ctx.status < 300 && ctx.body) {
72	      try {
73	        await idempotencyRepository.insert({
74	          accountId,
75	          key: idempotencyKey,
76	          requestFingerprint: fingerprint,
77	          responseStatus: ctx.status,
78	          responseBody: ctx.body,
79	        });
80	      } catch {
81	        // Best-effort — do not fail the request if idempotency storage fails
82	      }
83	    }
84	  };
85	}
