34	      absolute_expires_at: absoluteExpires.toISOString(),
35	      ip_address: meta.ipAddress || null,
36	      user_agent: meta.userAgent || null,
37	    });
38	
39	    return rawToken;
40	  },
41	
42	  /**
43	   * Validate a session token and rotate if needed.
43	   * Uses SELECT FOR UPDATE SKIP LOCKED to prevent concurrent rotation.
44	   *
45	   * Returns { user, newToken } where newToken is only set if rotation occurred.
46	   * The caller should send newToken in X-Session-Token response header.
47	   */
48	  async validateAndRotate(rawToken) {
49	    const tokenHash = hashToken(rawToken);
50	    const now = new Date();
51	
52	    // Use a transaction with FOR UPDATE SKIP LOCKED to prevent race conditions
53	    return knex.transaction(async (trx) => {
54	      // Look up by current or previous token hash (previous supports grace window)
55	      const session = await trx.raw(
56	        `
57	        SELECT s.*, a.id AS account_id, a.username, a.status AS account_status
58	        FROM sessions s
59	        JOIN accounts a ON a.id = s.account_id
60	        WHERE (s.token_hash = ? OR s.previous_token_hash = ?)
61	          AND s.invalidated_at IS NULL
62	          AND s.absolute_expires_at > NOW()
63	          AND s.idle_expires_at > NOW()
64	        LIMIT 1
65	        FOR UPDATE SKIP LOCKED
66	        `,
67	        [tokenHash, tokenHash],
68	      ).then((r) => r.rows[0]);
69	
70	      if (!session) {
71	        authFailuresTotal.inc({ reason: 'invalid_or_expired_token' });
72	        throw new AuthenticationError('Session not found or expired');
73	      }
74	
75	      if (session.account_status !== 'active') {
76	        authFailuresTotal.inc({ reason: 'account_inactive' });
77	        throw new AuthenticationError('Account is not active');
78	      }
79	
80	      let newToken = null;
81	      const isUsingPreviousToken = Buffer.compare(
82	        Buffer.from(tokenHash),
83	        Buffer.from(session.previous_token_hash || Buffer.alloc(0)),
84	      ) === 0;
85	
86	      if (isUsingPreviousToken) {
87	        // Enforce grace window: previous token is only valid for rotationGraceMs after rotation.
88	        // Without this check, a stolen previous token would remain valid indefinitely.
89	        const rotatedAtMs = session.rotated_at ? new Date(session.rotated_at).getTime() : 0;
90	        if (now.getTime() - rotatedAtMs > rotationGraceMs) {
91	          authFailuresTotal.inc({ reason: 'grace_expired' });
92	          throw new AuthenticationError('Session grace window expired — please re-authenticate');
93	        }
94	        // Update last_active_at only (do not re-rotate; client must use the already-issued token)
95	        await trx('sessions')
96	          .where({ id: session.id })
96	          .update({
97	            last_active_at: now.toISOString(),
98	            idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
99	          });
100	      } else {
101	        // Normal path: current token
102	        const timeSinceRotation = session.rotated_at
103	          ? now.getTime() - new Date(session.rotated_at).getTime()
104	          : Infinity;
105	
106	        if (timeSinceRotation > rotationIntervalMs) {
107	          // Rotate token
108	          newToken = generateOpaqueToken();
109	          const newTokenHash = hashToken(newToken);
110	
111	          await trx('sessions')
112	            .where({ id: session.id })
113	            .update({
114	              previous_token_hash: tokenHash,
115	              token_hash: newTokenHash,
116	              rotated_at: now.toISOString(),
117	              last_active_at: now.toISOString(),
118	              idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
119	            });
120	        } else {
121	          // Just update last_active_at
121	          await trx('sessions')
122	            .where({ id: session.id })
123	            .update({
124	              last_active_at: now.toISOString(),
125	              idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
126	            });
127	        }
128	      }
129	
130	      // Load user roles
131	      const roles = await trx('account_roles')
132	        .join('roles', 'roles.id', 'account_roles.role_id')
133	        .where('account_roles.account_id', session.account_id)
134	        .pluck('roles.name');
135	
136	      return {
137	        user: {
138	          id: session.account_id,
139	          username: session.username,
140	          roles,
141	        },
142	        newToken,
143	      };
144	    });
145	  },
146	
147	  /**
148	   * Invalidate a session (logout).
148	   */
149	  async invalidate(rawToken, reason = 'logout', trx) {
150	    const tokenHash = hashToken(rawToken);
151	    await (trx || knex)('sessions')
152	      .where(function () {
153	        this.where('token_hash', tokenHash).orWhere('previous_token_hash', tokenHash);
153	      })
154	      .whereNull('invalidated_at')
155	      .update({
156	        invalidated_at: new Date().toISOString(),
157	        invalidated_reason: reason,
158	      });
159	  },
160	
161	  /**
162	   * Invalidate all sessions for an account (e.g., on password change).
162	   */
163	  async invalidateAll(accountId, reason = 'password_change', trx) {
164	    await (trx || knex)('sessions')
164	      .where({ account_id: accountId })
165	      .whereNull('invalidated_at')
166	      .update({
167	        invalidated_at: new Date().toISOString(),
168	        invalidated_reason: reason,
169	      });
170	  },
171	};
