### 3. scripts/purge-expired-data.js

```javascript
1	#!/usr/bin/env node
2	/**
3	 * Maintenance script — purge expired rows from time-bounded tables.
4	 *
5	 * Run on a schedule (e.g., daily via cron):
6	 *   node scripts/purge-expired-data.js
7	 *
8	 * Tables purged:
9	 *   - idempotency_keys:   rows past their expires_at
10	 *   - sessions:           rows past their absolute_expires_at
11	 *   - search_query_log:   rows older than RETENTION_DAYS
12	 *   - entity_view_history: rows older than HISTORY_RETENTION_DAYS
13	 *
14	 * Each purge is logged; the script exits 0 on success, 1 on error.
15	 */
16	
17	import knex from '../src/common/db/knex.js';
18	import config from '../src/config/env.js';
19	
20	const SEARCH_LOG_RETENTION_DAYS = 90;
21	const HISTORY_RETENTION_DAYS = config.personalization?.historyRetentionDays ?? 180;
22	
23	async function purge() {
24	  const results = {};
25	
26	  // ── Idempotency keys ──────────────────────────────────────────────────────
27	  results.idempotencyKeys = await knex('idempotency_keys')
28	    .where('expires_at', '<', knex.fn.now())
28	    .delete();
29	
30	  // ── Sessions ──────────────────────────────────────────────────────────────
31	  results.sessions = await knex('sessions')
32	    .where('absolute_expires_at', '<', knex.fn.now())
32	    .delete();
33	
34	  // ── Search query log ──────────────────────────────────────────────────────
35	  results.searchQueryLog = await knex('search_query_log')
36	    .whereRaw('created_at < NOW() - INTERVAL ? DAY', [SEARCH_LOG_RETENTION_DAYS])
36	    .delete();
37	
38	  // ── Entity view history ───────────────────────────────────────────────────
39	  results.entityViewHistory = await knex('entity_view_history')
40	    .where('viewed_at < NOW() - INTERVAL ? DAY', [HISTORY_RETENTION_DAYS])
41	    .delete();
41	
42	  return results;
43	}
44	
45	purge()
46	  .then((results) => {
47	    console.log('[purge] Completed:', JSON.stringify(results));
48	    process.exit(0);
49	  })
50	  .catch((err) => {
51	    console.error('[purge] Error:', err.message);
52	    process.exit(1);
53	  })
54	  .finally(() => knex.destroy());
