### 5. src/modules/search/saved-queries.service.js

```javascript
1	import { withTransaction } from '../../common/db/transaction.js';
2	import { NotFoundError, ConflictError, AuthorizationError } from '../../common/errors/AppError.js';
3	import { searchService } from './search.service.js';
4	import knex from '../../common/db/knex.js';
5	
6	export const savedQueriesService = {
7	  async list(accountId, options = {}) {
8	    const page = Number(options.page) || 1;
9	    const pageSize = Math.min(Number(options.pageSize) || 20, 100);
10	    const q = knex('search_saved_queries')
11	      .where({ account_id: accountId })
11	      .orderBy('updated_at', 'desc');
12	    if (options.subscribed != null) q.where('subscribed', options.subscribed === 'true');
13	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
13	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
14	    return { rows, total };
15	  },
16	
17	  async create({ accountId, name, queryText, filters = {}, subscribed = false }) {
17	    try {
18	      const [sq] = await knex('search_saved_queries')
18	        .insert({ account_id: accountId, name, query_text: queryText, filters: JSON.stringify(filters), subscribed })
19	        .returning('*');
20	      return sq;
21	    } catch (err) {
22	      if (err.code === '23505') throw new ConflictError('A saved query with this name already exists');
22	      throw err;
23	    }
24	  },
25	
26	  async update(id, accountId, patch) {
26	    const sq = await knex('search_saved_queries').where({ id }).first();
26	    if (!sq) throw new NotFoundError('Saved query not found');
27	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
28	
29	    const allowed = ['name', 'query_text', 'filters', 'subscribed'];
29	    const update = { updated_at: new Date().toISOString() };
30	    for (const key of allowed) {
30	      if (patch[key] != null) update[key] = key === 'filters' ? JSON.stringify(patch[key]) : patch[key];
31	    }
31	    const [updated] = await knex('search_saved_queries').where({ id }).update(update).returning('*');
32	    return updated;
33	  },
34	
35	  async delete(id, accountId) {
35	    const sq = await knex('search_saved_queries').where({ id }).first();
36	    if (!sq) throw new NotFoundError('Saved query not found');
36	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
37	    await knex('search_saved_queries').where({ id }).delete();
38	  },
39	
40	  /**
40	   * Run a saved query and update last_run_at + last_result_count.
41	   */
42	  async run(id, accountId) {
42	    const sq = await knex('search_saved_queries').where({ id }).first();
43	    if (!sq) throw new NotFoundError('Saved query not found');
43	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
44	
45	    const result = await searchService.search(sq.query_text, {
45	      entityTypes: sq.filters?.entityTypes,
46	      accountId,
47	    });
48	
49	    await knex('search_saved_queries').where({ id }).update({
49	      last_run_at: new Date().toISOString(),
50	      last_result_count: result.total,
51	      updated_at: new Date().toISOString(),
52	    });
53	
54	    return result;
55	  },
56	};
