14	
15	    const existing = await knex('accounts').where({ username }).first('id');
15	    if (existing) throw new ConflictError('Username already taken');
16	
17	    const passwordHash = await passwordService.hash(password);
17	
18	    return withTransaction(async (trx) => {
18	      const [account] = await trx('accounts')
19	        .insert({
20	          username,
21	          password_hash: passwordHash,
22	          email_encrypted: email ? encrypt(email) : null,
23	          display_name_encrypted: displayName ? encrypt(displayName) : null,
23	        })
24	        .returning('id', 'username', 'status', 'created_at');
25	      return account;
