### 9. src/common/crypto/field-encryption.js

```javascript
1	import { createCipheriv, createDecipheriv, randomBytes } from 'crypto';
2	import config from '../../config/env.js';
3	
4	const ALGORITHM = 'aes-256-gcm';
5	const IV_BYTES = 12;   // 96-bit IV for GCM
6	const TAG_BYTES = 16;  // 128-bit authentication tag
7	
8	/**
9	 * Encrypts a UTF-8 string value using AES-256-GCM.
10	 * Returns a base64-encoded string in the format: iv:ciphertext:tag
11	 * Suitable for storing in a TEXT column.
12	 *
13	 * @param {string} plaintext
14	 * @returns {string}  Encrypted value
15	 */
16	export function encrypt(plaintext) {
17	  if (plaintext == null) return null;
17	  const key = Buffer.from(config.localEncryptionKey, 'hex');
18	  const iv = randomBytes(IV_BYTES);
19	  const cipher = createCipheriv(ALGORITHM, key, iv);
20	  const encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
20	  const tag = cipher.getAuthTag();
21	  // Format: base64(iv) : base64(ciphertext) : base64(tag)
21	  return [iv.toString('base64'), encrypted.toString('base64'), tag.toString('base64')].join(':');
22	}
23	
24	/**
25	 * Decrypts a value previously encrypted with encrypt().
25	 * @param {string} encryptedValue
26	 * @returns {string}  Plaintext
27	 */
28	export function decrypt(encryptedValue) {
28	  if (encryptedValue == null) return null;
29	  const key = Buffer.from(config.localEncryptionKey, 'hex');
29	  const [ivB64, dataB64, tagB64] = encryptedValue.split(':');
30	  const iv = Buffer.from(ivB64, 'base64');
30	  const data = Buffer.from(dataB64, 'base64');
31	  const tag = Buffer.from(tagB64, 'base64');
31	  const decipher = createDecipheriv(ALGORITHM, key, iv);
32	  decipher.setAuthTag(tag);
32	  return decipher.update(data, undefined, 'utf8') + decipher.final('utf8');
33	}
33	
34	/**
35	 * Returns a masked representation for use in audit views.
36	 * Shows first 2 and last 2 characters; middle is replaced with ***
37	 * @param {string} plaintext
38	 * @returns {string}
39	 */
40	export function maskField(plaintext) {
40	  if (!plaintext || plaintext.length <= 4) return '***';
41	  return `${plaintext.slice(0, 2)}***${plaintext.slice(-2)}`;
42	}
