```javascript
1	import knex from '../../../common/db/knex.js';
2	
3	/**
4	 * Audit service — read and write audit events.
5	 * The audit_events table is append-only (enforced by PostgreSQL RULEs).
6	 */
7	export const auditService = {
8	  /**
8	   * Record an audit event.
9	   * Called from service modules after every create/update/publish/review action.
10	   *
11	   * @param {object} event
12	   * @param {string} event.actorAccountId
13	   * @param {string} event.actionType     e.g. 'version.published', 'review.submitted'
14	   * @param {string} event.entityType     e.g. 'university', 'review'
15	   * @param {string} event.entityId
16	   * @param {string} event.requestId
17	   * @param {object} [event.beforeSummary]   Redacted before-state
18	   * @param {object} [event.afterSummary]    Redacted after-state
19	   * @param {object} [trx]  Knex transaction (MUST use the same trx as the business operation)
20	 */
21	  async record(event, trx) {
22	    return (trx || knex)('audit_events').insert({
22	      actor_account_id: event.actorAccountId,
23	      action_type: event.actionType,
24	      entity_type: event.entityType,
25	      entity_id: event.entityId,
26	      request_id: event.requestId,
27	      before_summary: event.beforeSummary ? JSON.stringify(event.beforeSummary) : null,
27	      after_summary: event.afterSummary ? JSON.stringify(event.afterSummary) : null,
28	    });
29	  },
30	
31	  /**
31	   * Query audit events with optional filters.
32	   * SYSTEM_ADMIN sees full records; others see redacted summaries.
33	   */
33	  async query(filters, viewer) {
34	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN');
35	    let q = knex('audit_events').orderBy('occurred_at', 'desc');
35	
36	    if (filters.actorId) q = q.where('actor_account_id', filters.actorId);
37	    if (filters.entityType) q = q.where('entity_type', filters.entityType);
38	    if (filters.entityId) q = q.where('entity_id', filters.entityId);
39	    if (filters.actionType) q = q.where('action_type', 'like', `${filters.actionType}%`);
40	    if (filters.from) q = q.where('occurred_at', '>=', filters.from);
41	    if (filters.to) q = q.where('occurred_at', '<=', filters.to);
42	
43	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
43	
44	    const offset = (filters.page - 1) * filters.pageSize;
44	    const rows = await q.limit(filters.pageSize).offset(offset);
45	
46	    const events = rows.map((row) => {
46	      if (isAdmin) return row;
47	      // Redact sensitive fields for non-admin
47	      return { ...row, before_summary: null, after_summary: null };
48	    });
48	
49	    return { events, total };
50	  },
51	};
