### 11. src/modules/search/search.service.js

```javascript
1	import knex from '../../common/db/knex.js';
2	import { searchConfig } from '../../config/search.js';
3	import { searchQueriesTotal } from '../../common/metrics/metrics.js';
4	
5	const { tsConfig, headline, activeVersionBoost, defaultPageSize, maxPageSize } = searchConfig;
6	
7	/**
8	 * Full-text search across all versioned university-data entities.
9	 *
9	 * Uses PostgreSQL's ts_rank_cd (cover density ranking) to score results.
10	 * Only active versions are searched by default; archived/superseded are excluded.
11	 */
12	export const searchService = {
13	  /**
13	   * Search across all entity types.
14	   *
15	   * @param {string} queryText
16	   * @param {object} options
17	   * @param {string[]} [options.entityTypes]  Filter to specific entity types
18	   * @param {number}  [options.page]
19	   * @param {number}  [options.pageSize]
20	   * @param {string}  [options.accountId]     For logging
20	   * @param {string}  [options.requestId]
21	   */
21	  /**
22	   * Expand a query term by looking up its synonyms in the search_synonyms table.
22	   * Returns an array of all terms (original + synonyms, deduplicated).
23	   */
24	  async _expandSynonyms(queryText) {
24	    const terms = queryText
25	      .toLowerCase()
26	      .split(/\s+/)
27	      .map((t) => t.replace(/[^a-z0-9]/gi, '').trim())
28	      .filter(Boolean);
29	
30	    if (!terms.length) return [queryText];
30	
31	    const rows = await knex('search_synonyms').whereIn('term', terms).select('term', 'synonyms');
31	    const synonymMap = new Map(rows.map((r) => [r.term, r.synonyms]));
32	
33	    const expanded = new Set([queryText]);
33	    for (const term of terms) {
34	      const synonyms = synonymMap.get(term) || [];
34	      for (const s of synonyms) {
35	        expanded.add(s);
36	      }
36	    }
37	    return [...expanded];
38	  },
39	
40	  async search(queryText, options = {}) {
40	    if (!queryText?.trim()) return { rows: [], total: 0, queryText };
41	    searchQueriesTotal.inc();
41	
42	    const pageSize = Math.min(options.pageSize || defaultPageSize, maxPageSize);
42	    const page = options.page || 1;
43	    const offset = (page - 1) * pageSize;
43	
44	    const entityTypes = options.entityTypes?.length ? options.entityTypes : null;
44	
45	    // Expand query with synonyms for richer recall
45	    const expandedTerms = await this._expandSynonyms(queryText);
46	
47	    // We use a UNION ALL across entity version tables — each entity emits the same columns
47	    const entityConfigs = [
48	      { table: 'university_versions',            entityType: 'university',            idCol: 'university_id' },
48	      { table: 'school_versions',                entityType: 'school',                idCol: 'school_id' },
49	      { table: 'major_versions',                 entityType: 'major',                 idCol: 'major_id' },
49	      { table: 'research_track_versions',        entityType: 'research_track',        idCol: 'research_track_id' },
50	      { table: 'enrollment_plan_versions',       entityType: 'enrollment_plan',       idCol: 'enrollment_plan_id' },
50	      { table: 'transfer_quota_versions',        entityType: 'transfer_quota',        idCol: 'transfer_quota_id' },
51	      { table: 'application_requirement_versions', entityType: 'application_requirement', idCol: 'application_requirement_id' },
51	      { table: 'retest_rule_versions',           entityType: 'retest_rule',           idCol: 'retest_rule_id' },
52	    ].filter((e) => !entityTypes || entityTypes.includes(e.entityType));
52	
53	    if (!entityConfigs.length) return { rows: [], total: 0, queryText };
53	
54	    const start = Date.now();
54	
55	    // Build a combined tsquery from the original term and all synonym expansions.
55	    // Each term becomes a websearch_to_tsquery clause joined with ||.
56	    // websearch_to_tsquery supports quoted phrases and exclusions; it also uses
56	    // the grad_search config (unaccent + english_stem) for normalisation.
57	    const tsqueryExpr = expandedTerms
57	      .map(() => `websearch_to_tsquery(?, ?)`)
58	      .join(' || ');
58	    const tsqueryParams = expandedTerms.flatMap((t) => [tsConfig, t]);
59	
60	    // Build UNION ALL query
60	    const unionParts = entityConfigs.map(({ table, entityType, idCol }) =>
61	      knex.raw(
61	        `
62	        SELECT
63	          ? AS entity_type,
63	          ${idCol} AS stable_id,
64	          id AS version_id,
64	          lifecycle_status,
65	          payload_json->>'name' AS name,
65	          payload_json->>'description' AS description,
66	          ts_rank_cd(search_vector, (${tsqueryExpr}))
66	            * CASE WHEN lifecycle_status = 'active' THEN ${activeVersionBoost} ELSE 1.0 END AS rank,
67	          ts_headline(
67	            ?,
68	            payload_json->>'name' || ' ' || COALESCE(payload_json->>'description', ''),
68	            (${tsqueryExpr}),
69	            ?
69	          ) AS headline
70	        FROM ${table}
70	        WHERE search_vector @@ (${tsqueryExpr})
71	          AND lifecycle_status IN ('active', 'scheduled', 'superseded')
71	        `,
72	        [
72	          entityType,
73	          ...tsqueryParams,
73	          tsConfig,
74	          ...tsqueryParams,
74	          `StartSel=${headline.startSel},StopSel=${headline.stopSel},MaxWords=${headline.maxWords},MinWords=${headline.minWords}`,
75	          ...tsqueryParams,
76	        ],
76	      ).toString()
77	    );
77	
78	    const unionSQL = unionParts.join('\nUNION ALL\n');
78	
79	    const results = await knex.raw(
79	      `
80	      SELECT * FROM (
81	        ${unionSQL}
81	      ) combined
82	      ORDER BY rank DESC
82	      LIMIT ? OFFSET ?
83	      `,
84	      [pageSize, offset],
84	    );
85	
86	    const countResult = await knex.raw(
86	      `
87	      SELECT COUNT(*) AS total FROM (
88	        ${unionSQL}
88	      ) combined
89	      `,
90	      [],
91	    );
91	
92	    const total = Number(countResult.rows[0]?.total || 0);
92	    const durationMs = Date.now() - start;
93	
94	    // Log query asynchronously (non-blocking)
94	    if (options.accountId) {
95	      knex('search_query_log')
95	        .insert({
96	          account_id: options.accountId,
97	          query_text: queryText.substring(0, 1000),
97	          entity_type: entityTypes?.join(',') || 'all',
98	          result_count: total,
98	          duration_ms: durationMs,
99	        })
99	        .catch(() => {}); // Never let logging failures affect the response
100	    }
101	
102	    return {
103	      rows: results.rows,
103	      total,
104	      queryText,
105	      durationMs,
106	    };
107	  },
107	
108	  /**
108	   * Suggest query completions based on existing entity names.
109	   * Returns up to 10 name prefixes.
110	   *
111	   * @param {string} prefix
111	   */
112	  async suggest(prefix) {
112	    if (!prefix?.trim() || prefix.length < 2) return [];
112	
113	    const tables = [
114	      'university_versions',
114	      'school_versions',
115	      'major_versions',
115	    ];
116	
117	    const parts = tables.map((t) =>
117	      knex(t)
118	        .where('lifecycle_status', 'active')
118	        .whereRaw("payload_json->>'name' ILIKE ?", [`${prefix}%`])
119	        .select(knex.raw("payload_json->>'name' AS name"))
119	        .limit(5)
120	    );
120	
121	    const results = await Promise.all(parts);
121	    const names = [...new Set(results.flat().map((r) => r.name).filter(Boolean))];
122	    return names.slice(0, 10);
122	  },
123	};
```

### 12. docs/security-model.md

```markdown
1	# Security Model
2	
3	## Authentication
4	
5	- **Method:** Username + password only (offline-safe, no external IdP)
6	- **Password hashing:** bcrypt at cost factor 12 (~300ms per check — documented latency)
7	- **Password rules:**
8	  - Minimum 12 characters
9	  - At least 3 of 4 character classes: uppercase, lowercase, digit, symbol
10	  - Cannot reuse any of the last 5 passwords (checked via bcrypt.compare loop)
11	- **Session token:** 256-bit opaque random token (`crypto.randomBytes(32).toString('hex')`)
12	  - Raw token is **never stored** — only `SHA-256(token)` stored in `token_hash BYTEA`
12	  - Idle timeout: 30 minutes (configurable via `SESSION_IDLE_TIMEOUT_MINUTES`)
13	  - Absolute timeout: 12 hours (configurable via `SESSION_ABSOLUTE_TIMEOUT_HOURS`)
14	  - Token rotation on activity: new token issued every 15 minutes of use
15	  - `SELECT ... FOR UPDATE SKIP LOCKED` prevents rotation race conditions
16	  - Grace window (30s) for concurrent requests during rotation via `previous_token_hash`
17	
18	## Authorization (Layered)
19	
19	### Layer 1 — Route-level capability check
20	Every protected route applies `requirePermission(resource, action)` middleware.
20	Capabilities are scoped to API groups (e.g., `university-data:publish`).
21	
22	### Layer 2 — Object-level ownership check
23	- Reviewers may only read/submit reviews for applications they are **assigned to**
23	- Users may only access their own personalization data
24	- Admin operations require SYSTEM_ADMIN or PROGRAM_ADMIN role
24	
25	### Layer 3 — Function-level guards
26	- Publish, archive, and assignment operations validate actor role in service logic
26	- Metrics and audit endpoints guard against non-admin access
27	
28	## Sensitive Data Handling
29	
29	Sensitive fields are encrypted at rest using **AES-256-GCM** with a locally managed key:
30	- Applicant contact identifiers
30	- Direct identity fields (name, contact info) supporting blind review workflows
31	31	
32	Key format: 32-byte key stored as 64-char hex string in `LOCAL_ENCRYPTION_KEY` env var.
33	Encrypted field format: `base64(iv):base64(ciphertext):base64(authTag)` stored in TEXT column.
33	
34	### Masked audit views
35	Sensitive fields are masked in audit output using `maskField()`: first 2 + `***` + last 2 chars.
35	
36	## Blind Review Mode
37	
37	Column selection happens in the **service layer** (not middleware or serializer):
38	- `blind`: only non-identity columns are included in the SQL SELECT
38	- `semi-blind`: academic context included; direct identity excluded
39	- `full`: all fields (SYSTEM_ADMIN and PROGRAM_ADMIN only)
40	40	
41	Identity data is **never fetched** in blind mode — a projection bug cannot cause a data leak.
41	
42	## Audit Logging
43	
43	The `audit_events` table is **append-only** enforced at the database level:
44	```sql
44	CREATE RULE no_update_audit AS ON UPDATE TO audit_events DO INSTEAD NOTHING;
45	CREATE RULE no_delete_audit AS ON DELETE TO audit_events DO INSTEAD NOTHING;
44	```
46	
47	Every create/update/publish/review action writes an audit event containing:
47	- `actor_account_id` — who performed the action
48	- `action_type` — what action (e.g., `version.published`, `review.submitted`)
48	- `entity_type` / `entity_id` — what was affected
49	- `occurred_at` — when (UTC timestamp)
49	- `request_id` — request trace ID
50	- `before_summary` / `after_summary` — redacted before/after state (no raw sensitive fields)
50	
51	## Log Redaction
52	
52	Pino redact list prevents sensitive values from appearing in structured logs:
53	```
53	req.headers.authorization
54	req.headers.cookie
54	req.body.password / *.password
55	req.body.password / *.password
55	*.token / *.tokenHash
56	*.hash
56	*.encryptionKey
57	```
57	
58	## Attachment Security
59	
59	- MIME type validated against allow-list via request `Content-Type` header
60	- Allowed: `application/pdf`, `image/png`, `image/jpeg`
60	- Max 5 attachments per review; max 10 MB per file
61	- SHA-256 fingerprint computed before write; stored as filename (content-addressed)
61	- Files stored outside the web root: `storage/attachments/{applicationId}/{reviewId}/{sha256}.{ext}`
62	- Path traversal is structurally prevented: the storage path is assembled from validated UUIDs and a SHA-256 hash — no user-supplied filename component reaches the filesystem
62	- Attachment metadata stored in DB; raw bytes are never logged
63	
64	## Admin / Internal Endpoint Protection
64	
65	| Endpoint | Protection |
65	|---|---|
66	| `GET /v1/admin/metrics` | Requires `metrics:read` (SYSTEM_ADMIN only) |
66	| `GET /v1/admin/audit-events` | Requires `audit:read` (SYSTEM_ADMIN, PROGRAM_ADMIN) |
67	| `GET /v1/admin/roles` | Requires `rbac:read` |
67	| `POST /v1/admin/roles` | Requires `rbac:write` (SYSTEM_ADMIN only) |
68	| `/health` | Public (no sensitive data) |
68	
69	No debug endpoints are exposed. No bypass flags exist in production.
69	
70	## Idempotency
71	
71	Write operations accept `Idempotency-Key` header:
72	- Key + SHA-256 fingerprint of `method + path + sorted(body)` stored
72	- Repeated same key + same body → return cached response (no duplicate side effects)
73	- Repeated same key + different body → `409 Conflict`
73	- Expiry: 24 hours
74	```

