67	  // ── Recommendations ────────────────────────────────────────────────────────
67	
68	  /**
68	   * Generate ranked recommendations with a deterministic explanation for each item.
69	   *
70	   * Scoring rules (applied in order, additive):
70	   *   +N   per view in the last 30 days (N = view count)
71	   *   +3   if bookmarked
71	   *   +2   if entity_type matches a tag subscription
72	   *
73	   * Cold-start: when the user has no signals at all, fall back to the 10 most
73	   * recently published active entities across all entity types.
74	   *
75	   * Each recommendation item includes a `reasons` array explaining the score,
75	   * making the output fully explainable.
76	   *
77	   * @param {string} accountId
77	   * @returns {Array<{entityType, stableId, score, reasons}>}
78	   */
79	  async getRecommendations(accountId) {
79	    const since = new Date();
80	    since.setDate(since.getDate() - 30);
80	
81	    recommendationGenerationsTotal.inc();
81	    const [views, bookmarks, tagSubs] = await Promise.all([
82	      knex('entity_view_history')
82	        .where('account_id', accountId)
83	        .where('viewed_at', '>=', since.toISOString())
83	        .select('entity_type', 'stable_id')
84	        .count('id as view_count')
84	        .groupBy('entity_type', 'stable_id')
85	        .orderBy('view_count', 'desc')
85	        .limit(50),
86	      knex('entity_bookmarks')
86	        .where('account_id', accountId)
87	        .select('entity_type', 'stable_id'),
87	      knex('tag_subscriptions')
88	        .where('account_id', accountId)
88	        .select('tag', 'tag_type'),
89	    ]);
89	
90	    const subscribedEntityTypes = new Set(
90	      tagSubs.filter((t) => t.tag_type === 'entity_type').map((t) => t.tag),
91	    );
91	
92	    // ── Cold-start path ───────────────────────────────────────────────────────
92	    if (!views.length && !bookmarks.length && !tagSubs.length) {
93	      const coldRecs = await this._coldStartRecommendations(accountId);
93	      await this._persistExplanations(accountId, coldRecs);
94	      return coldRecs;
94	    }
95	
96	    // ── Scored path ───────────────────────────────────────────────────────────
96	    const scoreMap = new Map();
97	
98	    const getOrCreate = (entityType, stableId) => {
98	      const key = `${entityType}:${stableId}`;
99	      if (!scoreMap.has(key)) {
99	        scoreMap.set(key, { entityType, stableId, score: 0, reasons: [] });
100	      }
100	      return scoreMap.get(key);
101	    };
101	
102	    for (const v of views) {
102	      const count = Number(v.view_count);
102	      const item = getOrCreate(v.entity_type, v.stable_id);
103	      item.score += count;
103	      item.reasons.push({ type: 'frequently_viewed', viewCount: count });
104	    }
104	
105	    for (const b of bookmarks) {
105	      const item = getOrCreate(b.entity_type, b.stable_id);
106	      item.score += 3;
106	      item.reasons.push({ type: 'bookmarked' });
107	    }
107	
108	    // Users with only tag subscriptions and no view/bookmark history produce an empty
108	    // scoreMap at this point. Seed it with popular entities from subscribed types so
109	    // the subscription boost below has something to apply to.
109	    if (subscribedEntityTypes.size > 0 && !scoreMap.size) {
110	      const seedItems = await this._coldStartRecommendations(accountId);
110	      for (const item of seedItems) {
111	        getOrCreate(item.entityType, item.stableId);
111	      }
112	    }
112	
113	    // Apply tag-subscription boost to all already-scored items of matching entity type
113	    for (const item of scoreMap.values()) {
113	      if (subscribedEntityTypes.has(item.entityType)) {
114	        item.score += 2;
114	        item.reasons.push({ type: 'tag_subscription', entityType: item.entityType });
115	      }
115	    }
116	
117	    const recommendations = [...scoreMap.values()]
117	      .sort((a, b) => b.score - a.score)
117	      .slice(0, 10);
118	
119	    await this._persistExplanations(accountId, recommendations);
119	    return recommendations;
120	  },
120	
121	  /**
121	   * Persist recommendation explanations for auditability.
121	   * Fire-and-forget (non-blocking) — never surfaces errors to the caller.
122	   */
123	  async _persistExplanations(accountId, recommendations) {
123	    if (!recommendations.length) return;
123	    const now = new Date().toISOString();
124	    const rows = recommendations.map((r) => ({
124	      account_id: accountId,
125	      entity_type: r.entityType,
125	      stable_id: r.stableId,
126	      score: r.score,
126	      reasons: JSON.stringify(r.reasons),
127	      generated_at: now,
127	    }));
128	    knex('recommendation_explanations').insert(rows).catch(() => {});
128	  },
128	
129	  /**
129	   * Cold-start fallback: return up to 10 recommended active entities.
129	   *
130	   * Signal priority:
130	   *   1. Declared interests — entity_type tag subscriptions narrow the candidate pool.
131	   *   2. Popularity         — global view count in the last 30 days ranks candidates.
132	   *   3. Recency            — tie-breaks by published_at DESC.
132	   *
133	   * Used when a user has no view history, bookmarks, or tag subscriptions of their own.
133	   */
134	  async _coldStartRecommendations(accountId) {
134	    const ENTITY_VERSION_TABLES = [
135	      { table: 'university_versions', entityType: 'university', idCol: 'university_id' },
135	      { table: 'major_versions',      entityType: 'major',      idCol: 'major_id' },
136	    ];
136	
137	    // Check declared-interest entity_type tag subscriptions
137	    const subscribedTypes = await knex('tag_subscriptions')
138	      .where({ account_id: accountId, tag_type: 'entity_type' })
138	      .pluck('tag');
139	
140	    const targetTables = subscribedTypes.length > 0
140	      ? ENTITY_VERSION_TABLES.filter((e) => subscribedTypes.includes(e.entityType))
140	      : ENTITY_VERSION_TABLES;
141	
142	    const since = new Date();
142	    since.setDate(since.getDate() - 30);
142	
143	    // Global popularity: total view count per entity in the last 30 days
143	    const popularity = await knex('entity_view_history')
143	      .select('entity_type', 'stable_id')
144	      .count('id as view_count')
144	      .where('viewed_at', '>=', since.toISOString())
145	      .groupBy('entity_type', 'stable_id');
145	
146	    const popularityMap = new Map(
146	      popularity.map((r) => [`${r.entity_type}:${r.stable_id}`, Number(r.view_count)]),
146	    );
147	
148	    const parts = await Promise.all(
148	      targetTables.map(({ table, entityType, idCol }) =>
148	        knex(table)
149	          .where('lifecycle_status', 'active')
149	          .orderBy('published_at', 'desc')
150	          .limit(20)
150	          .select(knex.raw(`'${entityType}' AS entity_type`), `${idCol} AS stable_id`, 'published_at'),
151	      ),
151	    );
152	
153	    const basis = subscribedTypes.length > 0 ? 'declared_interest' : 'recently_popular';
153	
154	    return parts
154	      .flat()
154	      .map((r) => ({
155	        entityType: r.entity_type,
155	        stableId: r.stable_id,
156	        publishedAt: r.published_at,
156	        popularity: popularityMap.get(`${r.entity_type}:${r.stable_id}`) || 0,
157	      }))
157	      .sort((a, b) => b.popularity - a.popularity || new Date(b.publishedAt) - new Date(a.publishedAt))
158	      .slice(0, 10)
158	      .map((r) => ({
159	        entityType: r.entityType,
159	        stableId: r.stableId,
160	        score: 0,
160	        reasons: [{ type: 'cold_start', basis }],
161	      }));
161	  },
162	};
