1	import { generateOpaqueToken, hashToken } from '../../common/crypto/tokens.js';
2	import { authConfig } from '../../config/auth.js';
3	import { AuthenticationError } from '../../common/errors/AppError.js';
4	import { authFailuresTotal } from '../../common/metrics/metrics.js';
5	import knex from '../../common/db/knex.js';
6	
7	const { idleTimeoutMs, absoluteTimeoutMs, rotationIntervalMs, rotationGraceMs } =
8	  authConfig.session;
9	
10	/**
11	 * Session service.
12	 * Manages opaque rotating session tokens stored in PostgreSQL.
13	 *
14	 * Security properties:
15	 * - Raw tokens never stored — only SHA-256 hash
16	 * - SELECT FOR UPDATE SKIP LOCKED prevents rotation race conditions
17	 * - Grace window (30s) handles concurrent requests during rotation
18	 * - Idle and absolute timeouts enforced at every request
19	 */
20	export const sessionService = {
21	  /**
22	   * Create a new session after successful login.
23	   * Returns the raw token (sent to client once — never stored).
24	   */
25	  async create(accountId, meta = {}, trx) {
26	    const rawToken = generateOpaqueToken();
27	    const tokenHash = hashToken(rawToken);
28	    const now = new Date();
29	    const idleExpires = new Date(now.getTime() + idleTimeoutMs);
30	    const absoluteExpires = new Date(now.getTime() + absoluteTimeoutMs);
31	
32	    await (trx || knex)('sessions').insert({
33	      account_id: accountId,
34	      token_hash: tokenHash,
35	      idle_expires_at: idleExpires.toISOString(),
36	      absolute_expires_at: absoluteExpires.toISOString(),
37	      ip_address: meta.ipAddress || null,
38	      user_agent: meta.userAgent || null,
39	    });
40	
41	    return rawToken;
42	  },
43	
44	  /**
45	   * Validate a session token and rotate if needed.
46	   * Uses SELECT FOR UPDATE SKIP LOCKED to prevent concurrent rotation.
47	   *
48	   * Returns { user, newToken } where newToken is only set if rotation occurred.
49	   * The caller should send newToken in X-Session-Token response header.
50	   */
51	  async validateAndRotate(rawToken) {
52	    const tokenHash = hashToken(rawToken);
53	    const now = new Date();
54	
55	    // Use a transaction with FOR UPDATE SKIP LOCKED to prevent race conditions
56	    return knex.transaction(async (trx) => {
57	      // Look up by current or previous token hash (previous supports grace window)
58	      const session = await trx.raw(
59	        `
60	        SELECT s.*, a.id AS account_id, a.username, a.status AS account_status
61	        FROM sessions s
62	        JOIN accounts a ON a.id = s.account_id
63	        WHERE (s.token_hash = ? OR s.previous_token_hash = ?)
64	          AND s.invalidated_at IS NULL
65	          AND s.absolute_expires_at > NOW()
66	          AND s.idle_expires_at > NOW()
67	        LIMIT 1
68	        FOR UPDATE SKIP LOCKED
69	        `,
70	        [tokenHash, tokenHash],
71	      ).then((r) => r.rows[0]);
72	
73	      if (!session) {
74	        authFailuresTotal.inc({ reason: 'invalid_or_expired_token' });
75	        throw new AuthenticationError('Session not found or expired');
76	      }
77	
78	      if (session.account_status !== 'active') {
79	        authFailuresTotal.inc({ reason: 'account_inactive' });
80	        throw new AuthenticationError('Account is not active');
81	      }
82	
83	      let newToken = null;
84	      const isUsingPreviousToken = Buffer.compare(
85	        Buffer.from(tokenHash),
86	        Buffer.from(session.previous_token_hash || Buffer.alloc(0)),
87	      ) === 0;
88	
89	      if (isUsingPreviousToken) {
90	        // Enforce grace window: previous token is only valid for rotationGraceMs after rotation.
91	        // Without this check, a stolen previous token would remain valid indefinitely.
92	        const rotatedAtMs = session.rotated_at ? new Date(session.rotated_at).getTime() : 0;
93	        if (now.getTime() - rotatedAtMs > rotationGraceMs) {
94	          authFailuresTotal.inc({ reason: 'grace_expired' });
95	          throw new AuthenticationError('Session grace window expired — please re-authenticate');
96	        }
97	        // Update last_active_at only (do not re-rotate; client must use the already-issued token)
98	        await trx('sessions')
99	          .where({ id: session.id })
100	          .update({
101	            last_active_at: now.toISOString(),
102	            idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
103	          });
104	      } else {
105	        // Normal path: current token
106	        const timeSinceRotation = session.rotated_at
107	          ? now.getTime() - new Date(session.rotated_at).getTime()
108	          : Infinity;
109	
110	        if (timeSinceRotation > rotationIntervalMs) {
111	          // Rotate token
112	          newToken = generateOpaqueToken();
113	          const newTokenHash = hashToken(newToken);
114	
115	          await trx('sessions')
116	            .where({ id: session.id })
117	            .update({
118	              previous_token_hash: tokenHash,
119	              token_hash: newTokenHash,
120	              rotated_at: now.toISOString(),
121	              last_active_at: now.toISOString(),
122	              idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
123	            });
124	        } else {
125	          // Just update last_active_at
126	          await trx('sessions')
127	            .where({ id: session.id })
128	            .update({
129	              last_active_at: now.toISOString(),
130	              idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
131	            });
132	        }
133	      }
134	
135	      // Load user roles
136	      const roles = await trx('account_roles')
137	        .join('roles', 'roles.id', 'account_roles.role_id')
138	        .where('account_roles.account_id', session.account_id)
139	        .pluck('roles.name');
140	
141	      return {
142	        user: {
143	          id: session.account_id,
144	          username: session.username,
145	          roles,
146	        },
147	        newToken,
148	      };
149	    });
150	  },
151	
152	  /**
153	   * Invalidate a session (logout).
154	   */
155	  async invalidate(rawToken, reason = 'logout', trx) {
156	    const tokenHash = hashToken(rawToken);
157	    await (trx || knex)('sessions')
158	      .where(function () {
159	        this.where('token_hash', tokenHash).orWhere('previous_token_hash', tokenHash);
160	      })
161	      .whereNull('invalidated_at')
162	      .update({
163	        invalidated_at: new Date().toISOString(),
164	        invalidated_reason: reason,
165	      });
166	  },
167	
168	  /**
169	   * Invalidate all sessions for an account (e.g., on password change).
170	   */
171	  async invalidateAll(accountId, reason = 'password_change', trx) {
172	    await (trx || knex)('sessions')
173	      .where({ account_id: accountId })
174	      .whereNull('invalidated_at')
175	      .update({
176	        invalidated_at: new Date().toISOString(),
177	        invalidated_reason: reason,
178	      });
179	  },
180	};
