2	/**
3	 * Maintenance script — purge expired rows from time-bounded tables.
4	 *
5	 * Run on a schedule (e.g., daily via cron):
6	 *   node scripts/purge-expired-data.js
7	 *
8	 * Tables purged:
9	 *   - idempotency_keys:   rows past their expires_at
10	 *   - sessions:           rows past their absolute_expires_at
11	 *   - search_query_log:   rows older than RETENTION_DAYS
12	 *   - entity_view_history: rows older than HISTORY_RETENTION_DAYS
13	 *
14	 * Each purge is logged; the script exits 0 on success, 1 on error.
15	 */
16	
17	import knex from '../src/common/db/knex.js';
18	import config from '../src/config/env.js';
19	
20	const SEARCH_LOG_RETENTION_DAYS = 90;
21	const HISTORY_RETENTION_DAYS = config.personalization?.historyRetentionDays ?? 180;
22	
23	async function purge() {
24	  const results = {};
25	
26	  // ── Idempotency keys ──────────────────────────────────────────────────────
27	  results.idempotencyKeys = await knex('idempotency_keys')
28	    .where('expires_at', '<', knex.fn.now())
29	    .delete();
30	
31	  // ── Sessions ──────────────────────────────────────────────────────────────
32	  results.sessions = await knex('sessions')
33	    .where('absolute_expires_at', '<', knex.fn.now())
34	    .delete();
35	
36	  // ── Search query log ──────────────────────────────────────────────────────
37	  results.searchQueryLog = await knex('search_query_log')
38	    .whereRaw('created_at < NOW() - INTERVAL ? DAY', [SEARCH_LOG_RETENTION_DAYS])
39	    .delete();
40	
41	  // ── Entity view history ───────────────────────────────────────────────────
42	  results.entityViewHistory = await knex('entity_view_history')
43	    .whereRaw('viewed_at < NOW() - INTERVAL ? DAY', [HISTORY_RETENTION_DAYS])
44	    .delete();
45	
46	  return results;
47	}
48	
49	purge()
50	  .then((results) => {
51	    console.log('[purge] Completed:', JSON.stringify(results));
52	    process.exit(0);
53	  })
54	  .catch((err) => {
55	    console.error('[purge] Error:', err.message);
56	    process.exit(1);
57	  })
58	  .finally(() => knex.destroy());
