1	import { withTransaction } from '../../common/db/transaction.js';
2	import { NotFoundError, ConflictError, AuthorizationError } from '../../common/errors/AppError.js';
3	import { searchService } from './search.service.js';
4	import knex from '../../common/db/knex.js';
5	
6	export const savedQueriesService = {
7	  async list(accountId, options = {}) {
8	    const page = Number(options.page) || 1;
9	    const pageSize = Math.min(Number(options.pageSize) || 20, 100);
10	    const q = knex('search_saved_queries')
11	      .where({ account_id: accountId })
12	      .orderBy('updated_at', 'desc');
13	    if (options.subscribed != null) q.where('subscribed', options.subscribed === 'true');
14	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
15	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
16	    return { rows, total };
17	  },
18	
19	  async create({ accountId, name, queryText, filters = {}, subscribed = false }) {
20	    try {
21	      const [sq] = await knex('search_saved_queries')
22	        .insert({ account_id: accountId, name, query_text: queryText, filters: JSON.stringify(filters), subscribed })
23	        .returning('*');
24	      return sq;
25	    } catch (err) {
26	      if (err.code === '23505') throw new ConflictError('A saved query with this name already exists');
27	      throw err;
28	    }
29	  },
30	
31	  async update(id, accountId, patch) {
32	    const sq = await knex('search_saved_queries').where({ id }).first();
33	    if (!sq) throw new NotFoundError('Saved query not found');
34	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
35	
36	    const allowed = ['name', 'query_text', 'filters', 'subscribed'];
37	    const update = { updated_at: new Date().toISOString() };
38	    for (const key of allowed) {
39	      if (patch[key] != null) update[key] = key === 'filters' ? JSON.stringify(patch[key]) : patch[key];
40	    }
41	    const [updated] = await knex('search_saved_queries').where({ id }).update(update).returning('*');
42	    return updated;
43	  },
44	
45	  async delete(id, accountId) {
46	    const sq = await knex('search_saved_queries').where({ id }).first();
47	    if (!sq) throw new NotFoundError('Saved query not found');
48	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
49	    await knex('search_saved_queries').where({ id }).delete();
50	  },
51	
52	  /**
53	   * Run a saved query and update last_run_at + last_result_count.
54	   */
55	  async run(id, accountId) {
56	    const sq = await knex('search_saved_queries').where({ id }).first();
57	    if (!sq) throw new NotFoundError('Saved query not found');
58	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
59	
60	    const result = await searchService.search(sq.query_text, {
61	      entityTypes: sq.filters?.entityTypes,
62	      accountId,
63	    });
64	
65	    await knex('search_saved_queries').where({ id }).update({
66	      last_run_at: new Date().toISOString(),
67	      last_result_count: result.total,
68	      updated_at: new Date().toISOString(),
69	    });
70	
71	    return result;
72	  },
73	};
