1	import Router from '@koa/router';
2	import { requirePermission } from '../../rbac/rbac.middleware.js';
3	import { validate } from '../../../common/middleware/validate.middleware.js';
4	import {
5	  publishVersionSchema,
6	  paginationSchema,
7	  versionParamsSchema,
8	} from './versioned.validator.js';
9	import { z } from 'zod';
10	
11	/**
12	 * Creates a standard versioned entity router.
13	 * All 8 university-data entities use this factory.
14	 *
15	 * @param {string} prefix       Route prefix e.g. '/universities'
16	 * @param {object} service      Versioned service instance
17	 * @param {object} createSchema Zod schema for create body
18	 * @param {object} fkFields     Map of camelCase body key → snake_case stable-table column
19	 *                              e.g. { universityId: 'university_id' } for schools
20	 */
21	export function makeVersionedRouter(prefix, service, createSchema, fkFields = {}) {
22	  const router = new Router({ prefix });
23	
24	  // POST /v1/{entity} — create entity + initial draft
25	  router.post(
26	    '/',
27	    requirePermission('university-data', 'write'),
28	    validate({ body: createSchema }),
29	    async (ctx) => {
30	      const { name } = ctx.request.body;
31	      const stableData = { name_normalized: name.toLowerCase().replace(/\s+/g, ' ').trim() };
32	      // Map entity-specific FK fields (camelCase from body → snake_case stable table column)
33	      for (const [camel, snake] of Object.entries(fkFields)) {
34	        if (ctx.request.body[camel] != null) stableData[snake] = ctx.request.body[camel];
35	      }
36	      const result = await service.create(stableData, ctx.request.body, ctx.state.user.id, ctx.state.requestId);
37	      ctx.status = 201;
38	      ctx.body = { data: result, meta: { requestId: ctx.state.requestId } };
39	    },
40	  );
41	
42	  // GET /v1/{entity} — list current active versions
43	  router.get(
44	    '/',
45	    requirePermission('university-data', 'read'),
46	    validate({ query: paginationSchema }),
47	    async (ctx) => {
48	      const result = await service.listCurrent({}, ctx.query);
49	      ctx.body = {
50	        data: result.rows,
51	        meta: { requestId: ctx.state.requestId, total: result.total, ...ctx.query },
52	      };
53	    },
54	  );
55	
56	  // GET /v1/{entity}/:stableId — get current active version
57	  router.get(
58	    '/:stableId',
59	    requirePermission('university-data', 'read'),
60	    async (ctx) => {
61	      const version = await service.findCurrent(ctx.params.stableId);
62	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
63	    },
64	  );
65	
66	  // GET /v1/{entity}/:stableId/current — alias
67	  router.get(
68	    '/:stableId/current',
69	    requirePermission('university-data', 'read'),
70	    async (ctx) => {
71	      const version = await service.findCurrent(ctx.params.stableId);
72	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
73	    },
74	  );
75	
76	  // GET /v1/{entity}/:stableId/versions — list version history
77	  router.get(
78	    '/:stableId/versions',
79	    requirePermission('university-data', 'read'),
80	    async (ctx) => {
81	      const history = await service.findHistory(ctx.params.stableId);
82	      ctx.body = {
83	        data: history,
84	        meta: { requestId: ctx.state.requestId, total: history.length },
85	      };
86	    },
87	  );
88	
89	  // GET /v1/{entity}/:stableId/versions/:versionId — specific version
90	  router.get(
91	    '/:stableId/versions/:versionId',
92	    requirePermission('university-data', 'read'),
93	    async (ctx) => {
94	      const version = await service.findVersionById(ctx.params.stableId, ctx.params.versionId);
95	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
96	    },
97	  );
98	
99	  // POST /v1/{entity}/:stableId/versions — create new draft
100	  router.post(
101	    '/:stableId/versions',
102	    requirePermission('university-data', 'write'),
103	    validate({ body: createSchema }),
104	    async (ctx) => {
105	      const version = await service.createNewDraft(
106	        ctx.params.stableId,
107	        ctx.request.body,
108	        ctx.state.user.id,
109	        ctx.state.requestId,
110	      );
111	      ctx.status = 201;
112	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
113	    },
114	  );
115	
116	  // PATCH /v1/{entity}/:stableId/versions/:versionId — update draft
117	  router.patch(
118	    '/:stableId/versions/:versionId',
119	    requirePermission('university-data', 'write'),
120	    async (ctx) => {
121	      const version = await service.updateDraft(
122	        ctx.params.stableId,
123	        ctx.params.versionId,
124	        ctx.request.body,
125	        ctx.state.user.id,
126	        ctx.state.requestId,
127	      );
128	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
129	    },
130	  );
131	
132	  // POST /v1/{entity}/:stableId/versions/:versionId/publish — publish version
133	  router.post(
134	    '/:stableId/versions/:versionId/publish',
135	    requirePermission('university-data', 'publish'),
136	    validate({ body: publishVersionSchema }),
137	    async (ctx) => {
138	      const version = await service.publish(
139	        ctx.params.stableId,
140	        ctx.params.versionId,
141	        ctx.state.user.id,
142	        ctx.state.requestId,
143	        ctx.request.body.effectiveFrom, // override stored effective_from if supplied
144	      );
145	      ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
146	    },
147	  );
148	
149	  // POST /v1/{entity}/:stableId/versions/:versionId/activate
150	  // Manually promotes the named scheduled version to active.
151	  // Rejects with 422 if the version's effective_from is still in the future.
152	  router.post(
153	    '/:stableId/versions/:versionId/activate',
154	    requirePermission('university-data', 'publish'),
155	    async (ctx) => {
156	      let version;
157	      try {
158	        version = await service.promoteScheduled(
159	          ctx.params.stableId,
160	          ctx.state.user.id,
161	          ctx.state.requestId,
162	          ctx.params.versionId,
163	        );
164	      } catch (err) {
165	        if (err.code === 'NOT_DUE') {
166	          ctx.status = 422;
167	          ctx.body = {
168	            error: { code: 'VERSION_NOT_DUE', message: err.message },
169	            meta: { requestId: ctx.state.requestId },
170	          };
171	          return;
172	        }
173	        throw err;
174	      }
175	      if (!version) {
176	        ctx.status = 404;
177	        ctx.body = {
178	          error: { code: 'NOT_FOUND', message: 'Version not found or not in scheduled state' },
179	          meta: { requestId: ctx.state.requestId },
180	        };
181	      } else {
182	        ctx.body = { data: version, meta: { requestId: ctx.state.requestId } };
183	      }
184	    },
185	  );
186	
187	  // POST /v1/{entity}/:stableId/archive — archive entity
188	  router.post(
189	    '/:stableId/archive',
190	    requirePermission('university-data', 'archive'),
191	    async (ctx) => {
192	      await service.archive(ctx.params.stableId, ctx.state.user.id, ctx.state.requestId);
193	      ctx.body = { data: { archived: true }, meta: { requestId: ctx.state.requestId } };
194	    },
195	  );
196	
197	  return router;
198	}
