1	import knex from '../../../common/db/knex.js';
2	
3	/**
4	 * Audit service — read and write audit events.
5	 * The audit_events table is append-only (enforced by PostgreSQL RULEs).
6	 */
7	export const auditService = {
8	  /**
9	   * Record an audit event.
10	   * Called from service modules after every create/update/publish/review action.
11	   *
12	   * @param {object} event
13	   * @param {string} event.actorAccountId
14	   * @param {string} event.actionType     e.g. 'version.published', 'review.submitted'
15	   * @param {string} event.entityType     e.g. 'university', 'review'
16	   * @param {string} event.entityId
17	   * @param {string} event.requestId
18	   * @param {object} [event.beforeSummary]   Redacted before-state
19	   * @param {object} [event.afterSummary]    Redacted after-state
20	   * @param {object} [trx]  Knex transaction (MUST use the same trx as the business operation)
21	   */
22	  async record(event, trx) {
23	    return (trx || knex)('audit_events').insert({
24	      actor_account_id: event.actorAccountId,
25	      action_type: event.actionType,
26	      entity_type: event.entityType,
27	      entity_id: event.entityId,
28	      request_id: event.requestId,
29	      before_summary: event.beforeSummary ? JSON.stringify(event.beforeSummary) : null,
30	      after_summary: event.afterSummary ? JSON.stringify(event.afterSummary) : null,
31	    });
32	  },
33	
34	  /**
35	   * Query audit events with optional filters.
36	   * SYSTEM_ADMIN sees full records; others see redacted summaries.
37	   */
38	  async query(filters, viewer) {
39	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN');
40	    let q = knex('audit_events').orderBy('occurred_at', 'desc');
41	
42	    if (filters.actorId) q = q.where('actor_account_id', filters.actorId);
43	    if (filters.entityType) q = q.where('entity_type', filters.entityType);
44	    if (filters.entityId) q = q.where('entity_id', filters.entityId);
45	    if (filters.actionType) q = q.where('action_type', 'like', `${filters.actionType}%`);
46	    if (filters.from) q = q.where('occurred_at', '>=', filters.from);
47	    if (filters.to) q = q.where('occurred_at', '<=', filters.to);
48	
49	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
50	
51	    const offset = (filters.page - 1) * filters.pageSize;
52	    const rows = await q.limit(filters.pageSize).offset(offset);
53	
54	    const events = rows.map((row) => {
55	      if (isAdmin) return row;
56	      // Redact sensitive fields for non-admin
57	      return { ...row, before_summary: null, after_summary: null };
58	    });
59	
60	    return { events, total };
61	  },
62	};
