6	const RETENTION_DAYS = config.personalization.historyRetentionDays;
7	
8	export const personalizationService = {
9	  // ── View history ───────────────────────────────────────────────────────────
10	
11	  async recordView({ accountId, entityType, stableId, versionId }) {
12	    await knex('entity_view_history').insert({
13	      account_id: accountId,
14	      entity_type: entityType,
15	      stable_id: stableId,
16	      version_id: versionId || null,
17	    });
18	  },
19	
20	  async getHistory(accountId, options = {}) {
21	    const pageSize = Math.min(options.pageSize || 20, 100);
22	    const page = options.page || 1;
23	    const since = new Date();
24	    since.setDate(since.getDate() - RETENTION_DAYS);
25	    const q = knex('entity_view_history')
26	      .where('account_id', accountId)
27	      .where('viewed_at', '>=', since.toISOString())
28	      .orderBy('viewed_at', 'desc');
29	    if (options.entityType) q.where('entity_type', options.entityType);
30	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
31	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
32	    return { rows, total };
33	  },
34	
35	  // ── Bookmarks ──────────────────────────────────────────────────────────────
36	
37	  async addBookmark({ accountId, entityType, stableId }) {
38	    try {
39	      const [bookmark] = await knex('entity_bookmarks')
40	        .insert({ account_id: accountId, entity_type: entityType, stable_id: stableId })
41	        .returning('*');
42	      return bookmark;
43	    } catch (err) {
44	      if (err.code === '23505') throw new ConflictError('Already bookmarked');
45	      throw err;
46	    }
47	  },
48	
49	  async removeBookmark({ accountId, entityType, stableId }) {
50	    const deleted = await knex('entity_bookmarks')
51	      .where({ account_id: accountId, entity_type: entityType, stable_id: stableId })
52	      .delete();
53	    if (!deleted) throw new NotFoundError('Bookmark not found');
54	  },
55	
56	  async getBookmarks(accountId, options = {}) {
57	    const pageSize = Math.min(options.pageSize || 20, 100);
58	    const page = options.page || 1;
59	    const q = knex('entity_bookmarks').where('account_id', accountId).orderBy('created_at', 'desc');
60	    if (options.entityType) q.where('entity_type', options.entityType);
61	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
62	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
63	    return { rows, total };
64	  },
65	
66	  // ── Preferences ────────────────────────────────────────────────────────────
67	
68	  async getPreferences(accountId) {
69	    const rows = await knex('user_preferences').where('account_id', accountId);
70	    // Return as a flat key→value map
71	    return Object.fromEntries(rows.map((r) => [r.pref_key, r.pref_value]));
72	  },
73	
74	  async setPreference(accountId, prefKey, prefValue) {
75	    const [pref] = await knex('user_preferences')
76	      .insert({
77	        account_id: accountId,
78	        pref_key: prefKey,
79	        pref_value: JSON.stringify(prefValue),
80	        updated_at: new Date().toISOString(),
81	      })
82	      .onConflict(['account_id', 'pref_key'])
83	      .merge(['pref_value', 'updated_at'])
84	      .returning('*');
85	    return pref;
86	  },
87	
88	  async deletePreference(accountId, prefKey) {
89	    const deleted = await knex('user_preferences')
90	      .where({ account_id: accountId, pref_key: prefKey })
91	      .delete();
92	    if (!deleted) throw new NotFoundError('Preference not found');
93	  },
94	
95	  // ── Tag subscriptions ──────────────────────────────────────────────────────
96	
97	  async getTagSubscriptions(accountId) {
98	    return knex('tag_subscriptions').where('account_id', accountId).orderBy('created_at', 'desc');
99	  },
100	
101	  async addTagSubscription({ accountId, tag, tagType = 'topic' }) {
102	    try {
103	      const [sub] = await knex('tag_subscriptions')
104	        .insert({ account_id: accountId, tag, tag_type: tagType })
105	        .returning('*');
106	      return sub;
107	    } catch (err) {
108	      if (err.code === '23505') throw new ConflictError('Already subscribed to this tag');
109	      throw err;
110	    }
111	  },
112	
113	  async removeTagSubscription({ accountId, tag }) {
114	    const deleted = await knex('tag_subscriptions')
115	      .where({ account_id: accountId, tag })
116	      .delete();
117	    if (!deleted) throw new NotFoundError('Tag subscription not found');
118	  },
119	
120	  // ── Recommendations ────────────────────────────────────────────────────────
121	
122	  /**
123	   * Generate ranked recommendations with a deterministic explanation for each item.
124	   *
125	   * Scoring rules (applied in order, additive):
126	   *   +N   per view in the last 30 days (N = view count)
127	   *   +3   if bookmarked
128	   *   +2   if entity_type matches a tag subscription
129	   *
130	   * Cold-start: when the user has no signals at all, fall back to the 10 most
131	   * recently published active entities across all entity types.
132	   *
133	   * Each recommendation item includes a `reasons` array explaining the score,
134	   * making the output fully explainable.
135	   *
136	   * @param {string} accountId
137	   * @returns {Array<{entityType, stableId, score, reasons}>}
138	   */
139	  async getRecommendations(accountId) {
140	    const since = new Date();
141	    since.setDate(since.getDate() - 30);
142	
143	    recommendationGenerationsTotal.inc();
144	    const [views, bookmarks, tagSubs] = await Promise.all([
145	      knex('entity_view_history')
146	        .where('account_id', accountId)
147	        .where('viewed_at', '>=', since.toISOString())
148	        .select('entity_type', 'stable_id')
149	        .count('id as view_count')
150	        .groupBy('entity_type', 'stable_id')
151	        .orderBy('view_count', 'desc')
152	        .limit(50),
153	      knex('entity_bookmarks')
154	        .where('account_id', accountId)
155	        .select('entity_type', 'stable_id'),
156	      knex('tag_subscriptions')
157	        .where('account_id', accountId)
158	        .select('tag', 'tag_type'),
159	    ]);
160	
161	    const subscribedEntityTypes = new Set(
162	      tagSubs.filter((t) => t.tag_type === 'entity_type').map((t) => t.tag),
163	    );
164	
165	    // ── Cold-start path ───────────────────────────────────────────────────────
166	    if (!views.length && !bookmarks.length && !tagSubs.length) {
167	      const coldRecs = await this._coldStartRecommendations(accountId);
168	      await this._persistExplanations(accountId, coldRecs);
169	      return coldRecs;
170	    }
171	
172	    // ── Scored path ───────────────────────────────────────────────────────────
173	    const scoreMap = new Map();
174	
175	    const getOrCreate = (entityType, stableId) => {
176	      const key = `${entityType}:${stableId}`;
177	      if (!scoreMap.has(key)) {
178	        scoreMap.set(key, { entityType, stableId, score: 0, reasons: [] });
179	      }
180	      return scoreMap.get(key);
181	    };
182	
183	    for (const v of views) {
184	      const count = Number(v.view_count);
185	      const item = getOrCreate(v.entity_type, v.stable_id);
186	      item.score += count;
187	      item.reasons.push({ type: 'frequently_viewed', viewCount: count });
188	    }
189	
190	    for (const b of bookmarks) {
191	      const item = getOrCreate(b.entity_type, b.stable_id);
192	      item.score += 3;
193	      item.reasons.push({ type: 'bookmarked' });
194	    }
195	
196	    // Users with only tag subscriptions and no view/bookmark history produce an empty
197	    // scoreMap at this point. Seed it with popular entities from subscribed types so
198	    // the subscription boost below has something to apply to.
199	    if (subscribedEntityTypes.size > 0 && !scoreMap.size) {
200	      const seedItems = await this._coldStartRecommendations(accountId);
201	      for (const item of seedItems) {
202	        getOrCreate(item.entityType, item.stableId);
203	      }
204	    }
205	
206	    // Apply tag-subscription boost to all already-scored items of matching entity type
207	    for (const item of scoreMap.values()) {
208	      if (subscribedEntityTypes.has(item.entityType)) {
209	        item.score += 2;
210	        item.reasons.push({ type: 'tag_subscription', entityType: item.entityType });
211	      }
212	    }
213	
214	    const recommendations = [...scoreMap.values()]
215	      .sort((a, b) => b.score - a.score)
216	      .slice(0, 10);
217	
218	    await this._persistExplanations(accountId, recommendations);
219	    return recommendations;
220	  },
221	
222	  /**
223	   * Persist recommendation explanations for auditability.
224	   * Fire-and-forget (non-blocking) — never surfaces errors to the caller.
225	   */
226	  async _persistExplanations(accountId, recommendations) {
227	    if (!recommendations.length) return;
228	    const now = new Date().toISOString();
229	    const rows = recommendations.map((r) => ({
230	      account_id: accountId,
231	      entity_type: r.entityType,
232	      stable_id: r.stableId,
233	      score: r.score,
234	      reasons: JSON.stringify(r.reasons),
235	      generated_at: now,
236	    }));
237	    knex('recommendation_explanations').insert(rows).catch(() => {});
238	  },
239	
240	  /**
241	   * Cold-start fallback: return up to 10 recommended active entities.
242	   *
243	   * Signal priority:
244	   *   1. Declared interests — entity_type tag subscriptions narrow the candidate pool.
245	   *   2. Popularity         — global view count in the last 30 days ranks candidates.
246	   *   3. Recency            — tie-breaks by published_at DESC.
247	   *
248	   * Used when a user has no view history, bookmarks, or tag subscriptions of their own.
249	   */
250	  async _coldStartRecommendations(accountId) {
251	    const ENTITY_VERSION_TABLES = [
252	      { table: 'university_versions', entityType: 'university', idCol: 'university_id' },
253	      { table: 'major_versions',      entityType: 'major',      idCol: 'major_id' },
254	    ];
255	
256	    // Check declared-interest entity_type tag subscriptions
257	    const subscribedTypes = await knex('tag_subscriptions')
258	      .where({ account_id: accountId, tag_type: 'entity_type' })
259	      .pluck('tag');
260	
261	    const targetTables = subscribedTypes.length > 0
262	      ? ENTITY_VERSION_TABLES.filter((e) => subscribedTypes.includes(e.entityType))
263	      : ENTITY_VERSION_TABLES;
264	
265	    const since = new Date();
266	    since.setDate(since.getDate() - 30);
267	
268	    // Global popularity: total view count per entity in the last 30 days
269	    const popularity = await knex('entity_view_history')
270	      .select('entity_type', 'stable_id')
271	      .count('id as view_count')
272	      .where('viewed_at', '>=', since.toISOString())
273	      .groupBy('entity_type', 'stable_id');
274	
275	    const popularityMap = new Map(
276	      popularity.map((r) => [`${r.entity_type}:${r.stable_id}`, Number(r.view_count)]),
277	    );
278	
279	    const parts = await Promise.all(
280	      targetTables.map(({ table, entityType, idCol }) =>
281	        knex(table)
282	          .where('lifecycle_status', 'active')
283	          .orderBy('published_at', 'desc')
284	          .limit(20)
285	          .select(knex.raw(`'${entityType}' AS entity_type`), `${idCol} AS stable_id`, 'published_at'),
286	      ),
287	    );
288	
289	    const basis = subscribedTypes.length > 0 ? 'declared_interest' : 'recently_popular';
290	
291	    return parts
292	      .flat()
293	      .map((r) => ({
294	        entityType: r.entity_type,
295	        stableId: r.stable_id,
296	        publishedAt: r.published_at,
297	        popularity: popularityMap.get(`${r.entity_type}:${r.stable_id}`) || 0,
298	      }))
299	      .sort((a, b) => b.popularity - a.popularity || new Date(b.publishedAt) - new Date(a.publishedAt))
300	      .slice(0, 10)
301	      .map((r) => ({
302	        entityType: r.entityType,
303	        stableId: r.stableId,
304	        score: 0,
305	        reasons: [{ type: 'cold_start', basis }],
306	      }));
307	  },
308	};
