1	import knex from '../../common/db/knex.js';
2	
3	/**
4	 * RBAC service.
5	 * Checks whether an account has a specific capability via its assigned roles.
6	 */
7	export const rbacService = {
8	  /**
9	   * Check if an account has permission to perform a capability.
10	   * @param {string} accountId
11	   * @param {string} capability  e.g. 'university-data:publish'
12	   * @returns {Promise<boolean>}
13	   */
14	  async can(accountId, capability) {
15	    const result = await knex('account_roles')
16	      .join('role_permissions', 'role_permissions.role_id', 'account_roles.role_id')
17	      .join('permissions', 'permissions.id', 'role_permissions.permission_id')
18	      .where('account_roles.account_id', accountId)
19	      .where('permissions.capability', capability)
20	      .first('permissions.id');
21	
22	    return Boolean(result);
23	  },
24	
25	  /**
26	   * Get all capabilities for an account.
27	   * @param {string} accountId
28	   * @returns {Promise<string[]>}
29	   */
30	  async getCapabilities(accountId) {
31	    return knex('account_roles')
32	      .join('role_permissions', 'role_permissions.role_id', 'account_roles.role_id')
33	      .join('permissions', 'permissions.id', 'role_permissions.permission_id')
34	      .where('account_roles.account_id', accountId)
35	      .pluck('permissions.capability');
36	  },
37	
38	  /**
39	   * Get all roles for an account.
40	   * @param {string} accountId
41	   * @returns {Promise<string[]>}
42	   */
43	  async getRoles(accountId) {
44	    return knex('account_roles')
45	      .join('roles', 'roles.id', 'account_roles.role_id')
46	      .where('account_roles.account_id', accountId)
47	      .pluck('roles.name');
48	  },
49	
50	  async listRoles() {
51	    return knex('roles').orderBy('name');
52	  },
53	
54	  async createRole({ name, description }, trx) {
55	    const [role] = await (trx || knex)('roles')
56	      .insert({ name, description })
57	      .returning('*');
58	    return role;
59	  },
60	
61	  async updateRole(roleId, patch, trx) {
62	    const [role] = await (trx || knex)('roles')
63	      .where({ id: roleId })
64	      .update(patch)
65	      .returning('*');
66	    return role;
67	  },
68	
69	  async assignRole(accountId, roleName, assignedBy, trx) {
70	    const role = await (trx || knex)('roles').where({ name: roleName }).first('id');
71	    if (!role) throw new Error(`Role ${roleName} not found`);
72	
73	    await (trx || knex)('account_roles')
74	      .insert({ account_id: accountId, role_id: role.id, assigned_by: assignedBy })
75	      .onConflict(['account_id', 'role_id'])
76	      .ignore();
77	  },
78	
79	  async listPermissions() {
80	    return knex('permissions').orderBy('capability');
81	  },
82	};
