1	import { z } from 'zod';
2	
3	/**
4	 * Shared Zod schemas for versioned entity operations.
5	 */
6	
7	// MM/DD/YYYY → YYYY-MM-DD conversion and validation
8	const effectiveDateSchema = z
9	  .string()
10	  .regex(/^\d{2}\/\d{2}\/\d{4}$/, 'Date must be MM/DD/YYYY format')
11	  .transform((s) => {
12	    const [mm, dd, yyyy] = s.split('/');
13	    return `${yyyy}-${mm}-${dd}`;
14	  })
15	  .or(
16	    // Also accept ISO format directly
17	    z.string().regex(/^\d{4}-\d{2}-\d{2}$/)
18	  );
19	
20	export const publishVersionSchema = z.object({
21	  effectiveFrom: effectiveDateSchema.optional(),
22	});
23	
24	export const createDraftSchema = z.object({
25	  effectiveFrom: effectiveDateSchema.optional(),
26	  changeSummary: z.string().max(500).optional(),
27	});
28	
29	export const paginationSchema = z.object({
30	  page: z.coerce.number().int().min(1).default(1),
31	  pageSize: z.coerce.number().int().min(1).max(100).default(20),
32	});
33	
34	export const versionParamsSchema = z.object({
35	  stableId: z.string().uuid(),
36	  versionId: z.string().uuid().optional(),
37	});
38	
39	/**
40	 * Creates a standard "create entity" schema with a required name + optional description.
41	 */
42	export function makeCreateEntitySchema(extraFields = {}) {
43	  return z.object({
44	    name: z.string().min(1).max(500),
45	    description: z.string().max(2000).optional(),
46	    effectiveFrom: effectiveDateSchema.optional(),
47	    changeSummary: z.string().max(500).optional(),
48	    ...extraFields,
49	  });
50	}
