1	import { requestFingerprint } from '../crypto/tokens.js';
2	import { idempotencyRepository } from './idempotency.repository.js';
3	import { ConflictError } from '../errors/AppError.js';
4	
5	// HTTP methods that require idempotency protection
6	const IDEMPOTENT_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
7	
8	/**
9	 * Idempotency-key middleware.
10	 *
11	 * For authenticated write requests (POST/PUT/PATCH/DELETE):
12	 *   - Missing Idempotency-Key header → 400 MISSING_IDEMPOTENCY_KEY
13	 *   - Key present, no prior record → execute handler, store response
14	 *   - Key present, matching fingerprint → return cached response (deduplication)
15	 *   - Key present, different fingerprint → 409 Conflict
16	 *
17	 * Unauthenticated write requests (e.g. POST /v1/auth/login) are exempt.
18	 */
19	export function idempotencyMiddleware() {
20	  return async function idempotency(ctx, next) {
21	    const idempotencyKey = ctx.get('Idempotency-Key');
22	
23	    // Skip non-write methods entirely
24	    if (!IDEMPOTENT_METHODS.has(ctx.method)) {
25	      await next();
26	      return;
27	    }
28	
29	    // Unauthenticated write requests (e.g. POST /v1/auth/login) bypass idempotency
30	    const accountId = ctx.state.user?.id;
31	    if (!accountId) {
32	      await next();
33	      return;
34	    }
35	
36	    // Authenticated write requests MUST supply an Idempotency-Key
37	    if (!idempotencyKey) {
38	      ctx.status = 400;
39	      ctx.body = {
40	        error: {
41	          code: 'MISSING_IDEMPOTENCY_KEY',
42	          message: 'Idempotency-Key header is required for authenticated write operations',
43	        },
44	        meta: { requestId: ctx.state.requestId },
45	      };
46	      return;
47	    }
48	
49	    const fingerprint = requestFingerprint(ctx.method, ctx.path, ctx.request.body || {});
50	
51	    // Check for existing record
52	    const existing = await idempotencyRepository.findByAccountAndKey(accountId, idempotencyKey);
53	
54	    if (existing) {
55	      if (existing.request_fingerprint !== fingerprint) {
56	        throw new ConflictError(
57	          'Idempotency key already used with a different request body',
58	        );
59	      }
60	      // Return cached response
61	      ctx.status = existing.response_status;
62	      const cached = typeof existing.response_body === 'string'
63	        ? JSON.parse(existing.response_body)
64	        : existing.response_body;
65	      // 204 responses have no body — only set if the cached payload is non-empty
66	      if (cached && Object.keys(cached).length > 0) {
67	        ctx.body = cached;
68	      }
69	      return;
70	    }
71	
72	    // Execute the actual handler
73	    await next();
74	
75	    // Store response for future deduplication — includes 204/no-body writes
76	    if (ctx.status >= 200 && ctx.status < 300) {
77	      try {
78	        await idempotencyRepository.insert({
79	          accountId,
80	          key: idempotencyKey,
81	          requestFingerprint: fingerprint,
82	          responseStatus: ctx.status,
83	          responseBody: ctx.body ?? {},
84	        });
85	      } catch {
86	        // Best-effort — do not fail the request if idempotency storage fails
87	      }
88	    }
89	  };
90	}
