22	export const auditService = {
23	  /**
24	   * Record an audit event.
25	   * Called from service modules after every create/update/publish/review action.
26	   *
27	   * @param {object} event
28	   * @param {string} event.actorAccountId
29	   * @param {string} event.actionType     e.g. 'version.published', 'review.submitted'
30	   * @param {string} event.entityType     e.g. 'university', 'review'
31	   * @param {string} event.entityId
32	   * @param {string} event.requestId
33	   * @param {object} [event.beforeSummary]   Redacted before-state
34	   * @param {object} [event.afterSummary]    Redacted after-state
35	   * @param {object} [trx]  Knex transaction (MUST use the same trx as the business operation)
36	   */
37	  async record(event, trx) {
38	    return (trx || knex)('audit_events').insert({
39	      actor_account_id: event.actorAccountId,
40	      action_type: event.actionType,
41	      entity_type: event.entityType,
42	      entity_id: event.entityId,
43	      request_id: event.requestId,
44	      before_summary: event.beforeSummary ? JSON.stringify(event.beforeSummary) : null,
45	      after_summary: event.afterSummary ? JSON.stringify(event.afterSummary) : null,
46	    });
47	  },
48	
49	  /**
50	   * Query audit events with optional filters.
51	   * SYSTEM_ADMIN sees full records; others see redacted summaries.
52	   */
53	  async query(filters, viewer) {
54	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN');
55	    let q = knex('audit_events').orderBy('occurred_at', 'desc');
56	
57	    if (filters.actorId) q = q.where('actor_account_id', filters.actorId);
58	    if (filters.entityType) q = q.where('entity_type', filters.entityType);
59	    if (filters.entityId) q = q.where('entity_id', filters.entityId);
60	    if (filters.actionType) q = q.where('action_type', 'like', `${filters.actionType}%`);
61	    if (filters.from) q = q.where('occurred_at', '>=', filters.from);
62	    if (filters.to) q = q.where('occurred_at', '<=', filters.to);
63	
64	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
65	
66	    const offset = (filters.page - 1) * filters.pageSize;
67	    const rows = await q.limit(filters.pageSize).offset(offset);
68	
69	    const events = rows.map((row) => {
70	      if (isAdmin) return row;
71	      // Mask string values in summaries for non-admin viewers (per security-model masked-view requirement)
72	      return {
73	        ...row,
74	        before_summary: maskSummary(row.before_summary),
75	        after_summary: maskSummary(row.after_summary),
76	      };
77	    });
78	
79	    return { events, total };
80	  },
81	};
