1	import Router from '@koa/router';
2	import { requirePermission } from '../rbac/rbac.middleware.js';
3	import { validate } from '../../common/middleware/validate.middleware.js';
4	import { searchService } from './search.service.js';
5	import { savedQueriesService } from './saved-queries.service.js';
6	import { z } from 'zod';
7	
8	export const searchRouter = new Router({ prefix: '/search' });
9	
10	const searchQuerySchema = z.object({
11	  q: z.string().min(1).max(500),
12	  entityTypes: z.string().optional().transform((v) => v?.split(',').filter(Boolean)),
13	  lifecycleStatus: z.string().optional().transform((v) => v?.split(',').filter(Boolean)),
14	  page: z.coerce.number().int().min(1).default(1),
15	  pageSize: z.coerce.number().int().min(1).max(100).default(20),
16	});
17	
18	const savedQuerySchema = z.object({
19	  name: z.string().min(1).max(200),
20	  queryText: z.string().min(1).max(500),
21	  filters: z.object({ entityTypes: z.array(z.string()).optional() }).optional(),
22	  subscribed: z.boolean().default(false),
23	});
24	
25	const savedQueryPatchSchema = z.object({
26	  name: z.string().min(1).max(200).optional(),
27	  queryText: z.string().min(1).max(500).optional(),
28	  filters: z.object({ entityTypes: z.array(z.string()).optional() }).optional(),
29	  subscribed: z.boolean().optional(),
30	}).refine((data) => Object.keys(data).length > 0, {
31	  message: 'At least one field must be provided',
32	});
33	
34	// GET /v1/search?q=<query>
35	searchRouter.get(
36	  '/',
37	  requirePermission('search', 'query'),
38	  validate({ query: searchQuerySchema }),
39	  async (ctx) => {
40	    const { q, entityTypes, lifecycleStatus, page, pageSize } = ctx.query;
41	    const result = await searchService.search(q, {
42	      entityTypes,
43	      lifecycleStatus,
44	      page,
45	      pageSize,
46	      accountId: ctx.state.user?.id,
47	      requestId: ctx.state.requestId,
48	    });
49	    ctx.body = {
50	      data: result.rows,
51	      meta: {
52	        requestId: ctx.state.requestId,
53	        total: result.total,
54	        query: result.queryText,
55	        durationMs: result.durationMs,
56	        page,
57	        pageSize,
58	      },
59	    };
60	  },
61	);
62	
63	// GET /v1/search/suggest?q=<prefix>
64	searchRouter.get(
65	  '/suggest',
66	  requirePermission('search', 'query'),
67	  async (ctx) => {
68	    const prefix = String(ctx.query.q || '');
69	    const suggestions = await searchService.suggest(prefix);
70	    ctx.body = { data: suggestions, meta: { requestId: ctx.state.requestId } };
71	  },
72	);
73	
74	// ── Saved queries ─────────────────────────────────────────────────────────────
75	
76	// GET /v1/search/saved-queries
77	searchRouter.get(
78	  '/saved-queries',
79	  requirePermission('search', 'saved-query:manage'),
80	  async (ctx) => {
81	    const result = await savedQueriesService.list(ctx.state.user.id, ctx.query);
82	    ctx.body = {
83	      data: result.rows,
84	      meta: { requestId: ctx.state.requestId, total: result.total },
85	    };
86	  },
87	);
88	
89	// POST /v1/search/saved-queries
90	searchRouter.post(
91	  '/saved-queries',
92	  requirePermission('search', 'saved-query:manage'),
93	  validate({ body: savedQuerySchema }),
94	  async (ctx) => {
95	    const sq = await savedQueriesService.create({
96	      accountId: ctx.state.user.id,
97	      ...ctx.request.body,
98	    });
99	    ctx.status = 201;
100	    ctx.body = { data: sq, meta: { requestId: ctx.state.requestId } };
101	  },
102	);
103	
104	// PATCH /v1/search/saved-queries/:id
105	searchRouter.patch(
106	  '/saved-queries/:id',
107	  requirePermission('search', 'saved-query:manage'),
108	  validate({ body: savedQueryPatchSchema }),
109	  async (ctx) => {
110	    const sq = await savedQueriesService.update(ctx.params.id, ctx.state.user.id, ctx.request.body);
111	    ctx.body = { data: sq, meta: { requestId: ctx.state.requestId } };
112	  },
113	);
114	
115	// DELETE /v1/search/saved-queries/:id
116	searchRouter.delete(
117	  '/saved-queries/:id',
118	  requirePermission('search', 'saved-query:manage'),
119	  async (ctx) => {
120	    await savedQueriesService.delete(ctx.params.id, ctx.state.user.id);
121	    ctx.status = 204;
122	  },
123	);
124	
125	// POST /v1/search/saved-queries/:id/run — execute a saved query
126	searchRouter.post(
127	  '/saved-queries/:id/run',
128	  requirePermission('search', 'saved-query:manage'),
129	  async (ctx) => {
130	    const result = await savedQueriesService.run(ctx.params.id, ctx.state.user.id);
131	    ctx.body = {
132	      data: result.rows,
133	      meta: { requestId: ctx.state.requestId, total: result.total, query: result.queryText },
134	    };
135	  },
136	);
