82	  /**
83	   * Batch assignment — randomly or by rules.
84	   * Assigns the minimum required number of reviewers to each application,
85	   * filtered by COI and load balance.
86	   *
87	   * @param {object} params
88	   * @param {string[]} params.applicationIds
89	   * @param {string} params.cycleId
90	   * @param {string} params.mode  'random' | 'rule_based'
91	   * @param {string} params.blindMode
92	   * @param {number} params.reviewersPerApplication
93	   * @param {string} params.assignedBy  Actor account ID
94	   */
95	  async batchAssign({ applicationIds, cycleId, mode, blindMode, reviewersPerApplication, assignedBy }, requestId) {
96	    const minReviewers = reviewersPerApplication || reviewPolicies.assignment.minReviewersPerApplication;
97	
98	    // Load eligible reviewers
99	    const eligibleReviewers = await knex('reviewer_profiles')
100	      .where({ available: true, active: true })
101	      .whereRaw('active_assignments < max_load')
102	      .select('id', 'expertise_tags', 'max_load', 'active_assignments');
103	
104	    if (eligibleReviewers.length === 0) {
105	      throw new UnprocessableError('No eligible reviewers available for assignment');
106	    }
107	
108	    // ── Rule-based: rank reviewers by expertise match per application ─────────
109	    // ── Random: shuffle pool once and apply uniformly ─────────────────────────
110	    let reviewerOrderByApp = null; // Map<appId, reviewer[]> — only set for rule_based
111	
112	    if (mode === 'rule_based') {
113	      // Load the program choices (major→field) for each application so we can
114	      // match against reviewer expertise_tags.
115	      const programRows = await knex('application_program_choices as apc')
116	        .join('major_versions as mv', function () {
117	          this.on('mv.major_id', '=', 'apc.major_id').andOn(
118	            'mv.lifecycle_status', '=', knex.raw("'active'"),
119	          );
120	        })
121	        .whereIn('apc.application_id', applicationIds)
122	        .select(
123	          'apc.application_id',
124	          knex.raw("LOWER(mv.payload_json->>'name') AS program_name"),
125	          knex.raw("LOWER(mv.payload_json->>'field') AS program_field"),
126	        );
127	
128	      // Build per-application keyword set
129	      const appKeywords = new Map(applicationIds.map((id) => [id, new Set()]));
130	      for (const row of programRows) {
131	        const kw = appKeywords.get(row.application_id);
132	        if (kw) {
133	          if (row.program_name) kw.add(row.program_name);
134	          if (row.program_field) kw.add(row.program_field);
135	        }
136	      }
137	
138	      // Score reviewers per application
139	      reviewerOrderByApp = new Map();
140	      for (const appId of applicationIds) {
141	        const keywords = appKeywords.get(appId) || new Set();
142	        const scored = eligibleReviewers.map((r) => {
143	          const tags = (r.expertise_tags || []).map((t) => String(t).toLowerCase());
144	          const matchCount = tags.filter((t) => keywords.has(t)).length;
145	          // Secondary sort: prefer reviewers with more available capacity
146	          const capacity = r.max_load - r.active_assignments;
147	          return { reviewer: r, matchCount, capacity };
148	        });
149	        // Sort: most expertise matches first, then most available capacity
150	        scored.sort((a, b) => b.matchCount - a.matchCount || b.capacity - a.capacity);
151	        reviewerOrderByApp.set(appId, scored.map((s) => s.reviewer));
152	      }
153	    }
154	
155	    const shuffledReviewers = secureShuffle(eligibleReviewers);
156	
157	    // Build candidate pairs for batch COI check
158	    const candidatePairs = [];
159	    for (const appId of applicationIds) {
160	      const reviewerList = reviewerOrderByApp ? reviewerOrderByApp.get(appId) : shuffledReviewers;
161	      for (const reviewer of (reviewerList || shuffledReviewers)) {
162	        candidatePairs.push({ reviewerId: reviewer.id, applicationId: appId });
163	      }
164	    }
165	
166	    // Batch COI check — returns set of conflicted pairs
167	    const conflictedPairs = await coiService.batchCheck(candidatePairs);
168	
169	    // Filter valid assignments per application.
170	    // reservedCounts tracks how many assignments have been planned for each reviewer
171	    // within this batch so we don't exceed max_load across multiple applications.
172	    const assignments = [];
173	    const errors = [];
174	    const reservedCounts = new Map();
175	
176	    for (const appId of applicationIds) {
177	      const orderedReviewers = reviewerOrderByApp
178	        ? (reviewerOrderByApp.get(appId) || shuffledReviewers)
179	        : shuffledReviewers;
180	
181	      const validReviewers = orderedReviewers.filter(
182	        (r) =>
183	          !conflictedPairs.has(`${r.id}:${appId}`) &&
184	          r.active_assignments + (reservedCounts.get(r.id) || 0) < r.max_load,
185	      );
186	
187	      if (validReviewers.length < minReviewers) {
188	        errors.push({ applicationId: appId, issue: 'Insufficient eligible reviewers after COI filtering' });
189	        continue;
190	      }
191	
192	      for (const reviewer of validReviewers.slice(0, minReviewers)) {
193	        assignments.push({
194	          application_id: appId,
195	          reviewer_id: reviewer.id,
196	          cycle_id: cycleId,
197	          assignment_mode: mode || 'random',
198	          blind_mode: blindMode || 'blind',
199	          assigned_by: assignedBy,
200	        });
201	        // Reserve capacity so subsequent applications in this batch see the updated load
202	        reservedCounts.set(reviewer.id, (reservedCounts.get(reviewer.id) || 0) + 1);
203	      }
204	    }
205	
206	    if (assignments.length === 0) {
207	      throw new UnprocessableError('No valid assignments could be created', errors);
208	    }
