111	  async submit({ assignmentId, criterionScores, narrativeComments, recommendation }, actorId, requestId) {
112	    if (!recommendation) {
113	      throw new UnprocessableError('A recommendation is required before submitting');
114	    }
115	
116	    const assignment = await knex('review_assignments')
117	      .where({ id: assignmentId })
118	      .first();
119	    if (!assignment) throw new NotFoundError('Assignment not found');
120	
121	    const reviewerProfile = await knex('reviewer_profiles')
122	      .where({ account_id: actorId })
123	      .first('id');
124	    if (!reviewerProfile || assignment.reviewer_id !== reviewerProfile.id) {
125	      throw new AuthorizationError('You are not assigned to this review');
126	    }
127	
128	    if (!['assigned', 'accepted'].includes(assignment.status)) {
129	      throw new UnprocessableError('Assignment is not in a submittable state');
130	    }
