157	    const composite = computeComposite(criterionScores, template.criteria_schema);
158	    const now = new Date().toISOString();
159	
160	    return withTransaction(async (trx) => {
161	      const [score] = await trx('review_scores')
162	        .insert({
163	          assignment_id: assignmentId,
164	          template_id: template.id,
165	          criterion_scores: JSON.stringify(criterionScores),
166	          composite_score: composite,
167	          narrative_comments: narrativeComments || null,
168	          recommendation,
