17	/**
18	 * Tests for trimmed mean and variance logic in the aggregation service.
19	 * The private helpers are tested indirectly via the exported service.
20	 *
21	 * Trimming rule (config): 10% from each end, requires ≥7 scores to apply.
22	 */
23	
24	// We test the pure math functions extracted from the service logic here,
25	// since the private helpers are not exported.  Mirror the exact algorithm.
26	
27	function trimmedMean(scores, { trimEnabled, trimPercent, trimMinCount }) {
28	  if (!trimEnabled || scores.length < trimMinCount) {
29	    if (!scores.length) return null;
30	    return scores.reduce((a, b) => a + b, 0) / scores.length;
31	  }
32	  const sorted = [...scores].sort((a, b) => a - b);
33	  const trimCount = Math.floor((trimPercent / 100) * sorted.length);
34	  const trimmed = sorted.slice(trimCount, sorted.length - trimCount);
35	  if (!trimmed.length) return null;
36	  return trimmed.reduce((a, b) => a + b, 0) / trimmed.length;
37	}
38	
39	function variance(scores, mean) {
40	  if (scores.length < 2) return 0;
41	  return scores.map((s) => Math.pow(s - mean, 2)).reduce((a, b) => a + b, 0) / scores.length;
42	}
43	
44	const POLICY = { trimEnabled: true, trimPercent: 10, trimMinCount: 7 };
45	
46	describe('trimmedMean', () => {
47	  it('returns null for empty array', () => {
48	    expect(trimmedMean([], POLICY)).toBeNull();
49	  });
50	
51	  it('falls back to plain mean when fewer than trimMinCount scores', () => {
52	    const scores = [1, 2, 3, 4, 5]; // < 7
53	    const mean = scores.reduce((a, b) => a + b, 0) / scores.length; // 3
54	    expect(trimmedMean(scores, POLICY)).toBe(mean);
55	  });
56	
57	  it('trims outliers when ≥ trimMinCount scores present', () => {
58	    // 10 scores: [1, 1, 5, 5, 5, 5, 5, 5, 9, 9]
59	    // 10% trim = 1 from each end → [1, 5, 5, 5, 5, 5, 5, 9]
60	    const scores = [9, 1, 5, 5, 5, 5, 5, 5, 9, 1];
61	    const result = trimmedMean(scores, POLICY);
62	    const sorted = [1, 1, 5, 5, 5, 5, 5, 5, 9, 9];
63	    const trimmed = sorted.slice(1, 9); // [1, 5, 5, 5, 5, 5, 5, 9]
64	    const expected = trimmed.reduce((a, b) => a + b, 0) / trimmed.length;
65	    expect(result).toBeCloseTo(expected, 3);
66	  });
67	
