70	    const without    = [7, 7, 8, 8, 8, 8, 8, 8]; // trimmed
71	    const trimmed = trimmedMean(withOutlier, POLICY);
72	    const plain = withOutlier.reduce((a, b) => a + b, 0) / withOutlier.length;
73	    // Trimmed mean should be higher than plain (outlier 0 pulled plain down)
74	    expect(trimmed).toBeGreaterThan(plain);
75	  });
76	});
