5	// HTTP methods that require idempotency protection
6	const IDEMPOTENT_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
7	
8	/**
9	 * Idempotency-key middleware.
10	 *
11	 * For authenticated write requests (POST/PUT/PATCH/DELETE):
12	 *   - Missing Idempotency-Key header → 400 MISSING_IDEMPOTENCY_KEY
13	 *   - Key present, no prior record → reserve slot, execute handler, complete slot
14	 *   - Key present, matching fingerprint, completed → return cached response (deduplication)
15	 *   - Key present, matching fingerprint, pending → 409 (concurrent in-flight request)
16	 *   - Key present, different fingerprint → 409 Conflict
17	 *
18	 * Unauthenticated write requests (e.g. POST /v1/auth/login) are exempt.
19	 *
20	 * Atomicity guarantee: the slot is reserved via INSERT … ON CONFLICT DO NOTHING
21	 * before the handler runs, so two concurrent requests with the same key race at the
22	 * DB level. Only one wins the INSERT; the other finds the existing record and either
23	 * replays the cached response or returns 409 (still pending).
24	 */
25	export function idempotencyMiddleware() {
26	  return async function idempotency(ctx, next) {
27	    const idempotencyKey = ctx.get('Idempotency-Key');
28	
29	    // Skip non-write methods entirely
30	    if (!IDEMPOTENT_METHODS.has(ctx.method)) {
31	      await next();
32	      return;
33	    }
34	
35	    // Unauthenticated write requests (e.g. POST /v1/auth/login) bypass idempotency
36	    const accountId = ctx.state.user?.id;
37	    if (!accountId) {
38	      await next();
39	      return;
40	    }
41	
42	    // Authenticated write requests MUST supply an Idempotency-Key
43	    if (!idempotencyKey) {
44	      ctx.status = 400;
45	      ctx.body = {
46	        error: {
47	          code: 'MISSING_IDEMPOTENCY_KEY',
48	          message: 'Idempotency-Key header is required for authenticated write operations',
49	        },
50	        meta: { requestId: ctx.state.requestId },
51	      };
52	      return;
53	    }
54	
55	    const fingerprint = requestFingerprint(ctx.method, ctx.path, ctx.request.body || {});
56	
57	    // Attempt to atomically reserve the slot before running the handler.
58	    // If reserve returns false, a record already exists for this (account, key).
59	    const reserved = await idempotencyRepository.reserve(accountId, idempotencyKey, fingerprint);
60	
61	    if (!reserved) {
62	      // Slot already existed — look up the record to decide what to return
63	      const existing = await idempotencyRepository.findByAccountAndKey(accountId, idempotencyKey);
64	
65	      if (!existing) {
66	        // Record existed when we tried to insert but has since expired — treat as new
67	        // Re-attempt the reserve; if it fails again another request is truly concurrent
68	        const retried = await idempotencyRepository.reserve(accountId, idempotencyKey, fingerprint);
69	        if (!retried) {
70	          ctx.status = 409;
71	          ctx.body = {
72	            error: {
73	              code: 'IDEMPOTENCY_KEY_IN_FLIGHT',
74	              message: 'A request with this Idempotency-Key is already being processed',
75	            },
76	            meta: { requestId: ctx.state.requestId },
77	          };
78	          return;
79	        }
80	        // Successfully reserved on retry — fall through to handler execution below
81	      } else {
82	        if (existing.request_fingerprint !== fingerprint) {
83	          throw new ConflictError(
84	            'Idempotency key already used with a different request body',
85	          );
86	        }
87	
88	        if (existing.response_status === 0) {
89	          // Still pending — concurrent in-flight request
90	          ctx.status = 409;
91	          ctx.body = {
92	            error: {
93	              code: 'IDEMPOTENCY_KEY_IN_FLIGHT',
94	              message: 'A request with this Idempotency-Key is already being processed',
95	            },
96	            meta: { requestId: ctx.state.requestId },
97	          };
98	          return;
99	        }
100	
101	        // Completed — replay cached response
102	        ctx.status = existing.response_status;
103	        const cached = typeof existing.response_body === 'string'
104	          ? JSON.parse(existing.response_body)
105	          : existing.response_body;
106	        // 204 responses have no body — only set if the cached payload is non-empty
107	        if (cached && Object.keys(cached).length > 0) {
108	          ctx.body = cached;
109	        }
110	        return;
111	      }
112	    }
113	
114	    // Slot is now reserved — execute the handler
115	    try {
116	      await next();
117	    } catch (err) {
118	      // Handler failed — remove the pending slot so the client can retry
119	      await idempotencyRepository.deletePending(accountId, idempotencyKey).catch(() => {});
120	      throw err;
121	    }
122	
123	    // Handler succeeded — complete the slot with the real response
124	    if (ctx.status >= 200 && ctx.status < 300) {
125	      await idempotencyRepository.complete(
126	        accountId,
127	        idempotencyKey,
128	        ctx.status,
129	        ctx.body ?? {},
130	      ).catch(() => {
131	        // Best-effort — do not fail the request if idempotency storage fails
132	      });
133	    } else {
134	      // Non-2xx (e.g. validation error that slipped through) — release the slot
135	      await idempotencyRepository.deletePending(accountId, idempotencyKey).catch(() => {});
136	    }
137	  };
138	}
