44	  /**
45	   * Validate a session token and rotate if needed.
46	   * Uses SELECT FOR UPDATE SKIP LOCKED to prevent concurrent rotation.
47	   *
48	   * Returns { user, newToken } where newToken is only set if rotation occurred.
49	   * The caller should send newToken in X-Session-Token response header.
50	   */
51	  async validateAndRotate(rawToken) {
52	    const tokenHash = hashToken(rawToken);
53	    const now = new Date();
54	
55	    // Use FOR UPDATE NOWAIT with one retry to handle transient lock contention.
56	    // SKIP LOCKED can silently miss a locked row and return null, causing spurious 401s
57	    // when two concurrent requests arrive during a rotation window.
58	    return knex.transaction(async (trx) => {
59	      let session;
60	      let lockAttempt = 0;
61	      while (true) {
62	        try {
63	          session = await trx.raw(
64	            `
65	            SELECT s.*, a.id AS account_id, a.username, a.status AS account_status
66	            FROM sessions s
67	            JOIN accounts a ON a.id = s.account_id
68	            WHERE (s.token_hash = ? OR s.previous_token_hash = ?)
69	              AND s.invalidated_at IS NULL
70	              AND s.absolute_expires_at > NOW()
71	              AND s.idle_expires_at > NOW()
72	            LIMIT 1
73	            FOR UPDATE NOWAIT
74	            `,
75	            [tokenHash, tokenHash],
76	          ).then((r) => r.rows[0]);
77	          break;
78	        } catch (err) {
79	          // 55P03 = lock_not_available (FOR UPDATE NOWAIT); retry once with brief backoff
80	          if (err.code === '55P03' && lockAttempt < 1) {
81	            lockAttempt++;
82	            await new Promise((resolve) => setTimeout(resolve, 50));
83	            continue;
84	          }
85	          throw err;
86	        }
87	      }
88	
89	      if (!session) {
90	        authFailuresTotal.inc({ reason: 'invalid_or_expired_token' });
91	        throw new AuthenticationError('Session not found or expired');
92	      }
93	
94	      if (session.account_status !== 'active') {
95	        authFailuresTotal.inc({ reason: 'account_inactive' });
96	        throw new AuthenticationError('Account is not active');
97	      }
98	
99	      let newToken = null;
100	      const isUsingPreviousToken = Buffer.compare(
101	        Buffer.from(tokenHash),
102	        Buffer.from(session.previous_token_hash || Buffer.alloc(0)),
103	      ) === 0;
104	
105	      if (isUsingPreviousToken) {
106	        // Enforce grace window: previous token is only valid for rotationGraceMs after rotation.
107	        // Without this check, a stolen previous token would remain valid indefinitely.
108	        const rotatedAtMs = session.rotated_at ? new Date(session.rotated_at).getTime() : 0;
109	        if (now.getTime() - rotatedAtMs > rotationGraceMs) {
110	          authFailuresTotal.inc({ reason: 'grace_expired' });
111	          throw new AuthenticationError('Session grace window expired — please re-authenticate');
112	        }
113	        // Update last_active_at only (do not re-rotate; client must use the already-issued token)
114	        await trx('sessions')
115	          .where({ id: session.id })
116	          .update({
117	            last_active_at: now.toISOString(),
118	            idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
119	          });
120	      } else {
121	        // Normal path: current token
122	        const timeSinceRotation = session.rotated_at
123	          ? now.getTime() - new Date(session.rotated_at).getTime()
124	          : Infinity;
125	
126	        if (timeSinceRotation > rotationIntervalMs) {
127	          // Rotate token
128	          newToken = generateOpaqueToken();
129	          const newTokenHash = hashToken(newToken);
130	
131	          await trx('sessions')
132	            .where({ id: session.id })
133	            .update({
134	              previous_token_hash: tokenHash,
135	              token_hash: newTokenHash,
136	              rotated_at: now.toISOString(),
137	              last_active_at: now.toISOString(),
138	              idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
139	            });
140	        } else {
141	          // Just update last_active_at
142	          await trx('sessions')
143	            .where({ id: session.id })
144	            .update({
145	              last_active_at: now.toISOString(),
146	              idle_expires_at: new Date(now.getTime() + idleTimeoutMs).toISOString(),
147	            });
148	        }
149	      }
150	
151	      // Load user roles
152	      const roles = await trx('account_roles')
153	        .join('roles', 'roles.id', 'account_roles.role_id')
154	        .where('account_roles.account_id', session.account_id)
155	        .pluck('roles.name');
156	
157	      return {
158	        user: {
159	          id: session.account_id,
160	          username: session.username,
161	          roles,
162	        },
163	        newToken,
164	      };
165	    });
166	  },
167	
168	  /**
169	   * Invalidate a session (logout).
170	   */
171	  async invalidate(rawToken, reason = 'logout', trx) {
172	    const tokenHash = hashToken(rawToken);
173	    await (trx || knex)('sessions')
174	      .where(function () {
175	        this.where('token_hash', tokenHash).orWhere('previous_token_hash', tokenHash);
176	      })
177	      .whereNull('invalidated_at')
178	      .update({
179	        invalidated_at: new Date().toISOString(),
