60	// Helper: mirror the exact computeComposite algorithm
61	function computeComposite(criterionScores, criteriaSchema) {
62	  const criteria = criteriaSchema?.criteria ?? [];
63	  if (!criteria.length) return null;
64	  let weightedSum = 0;
65	  let totalWeight = 0;
66	  for (const criterion of criteria) {
67	    const raw = criterionScores[criterion.id];
68	    if (raw == null) continue;
69	    const normalised = (raw / criterion.maxScore) * 10;
70	    weightedSum += normalised * criterion.weight;
71	    totalWeight += criterion.weight;
72	  }
73	  if (totalWeight === 0) return null;
74	  return Math.round((weightedSum / totalWeight) * 1000) / 1000;
75	}
