28	  const app = new Koa();
29	
30	  // Trust proxy headers in production
31	  if (config.isProduction) {
32	    app.proxy = true;
33	  }
34	
35	  // Global error handler for errors not caught by error-handler middleware
36	  app.on('error', (err, ctx) => {
37	    if (!ctx || ctx.status < 500) return; // Already logged by middleware
38	    logger.error({ err, requestId: ctx?.state?.requestId }, 'Koa app-level error');
39	  });
40	
