48	    try {
49	      await next();
50	    } finally {
51	      logger.info(
52	        { requestId: ctx.state.requestId, method: ctx.method, path: ctx.path, status: ctx.status, ms: Date.now() - start },
53	        'request end',
54	      );
55	    }
56	  });
57	
58	  app.use(metricsMiddleware());
59	  app.use(errorHandlerMiddleware(logger));
60	
