62	    koaBody({
63	      json: true,
64	      multipart: true,
65	      formidable: {
66	        maxFileSize: config.attachments.maxFileBytes,
67	        maxFields: 20,
68	      },
69	      jsonLimit: '1mb',
70	      textLimit: '1mb',
71	    }),
