3	/**
4	 * Koa error-handling middleware.
5	 * Must be the outermost middleware (registered before the router) so it catches
6	 * all errors thrown during request processing.
7	 *
8	 * Distinguishes AppError (expected, client-facing) from unexpected errors and
9	 * logs at the appropriate level.
10	 */
11	export function errorHandlerMiddleware(logger) {
12	  return async function errorHandler(ctx, next) {
13	    try {
14	      await next();
15	    } catch (err) {
16	      const requestId = ctx.state.requestId || 'unknown';
17	
18	      if (err instanceof AppError) {
19	        ctx.status = err.statusCode;
20	        ctx.body = {
21	          error: {
22	            code: err.code,
23	            message: err.message,
24	            ...(err.details?.length ? { details: err.details } : {}),
25	          },
26	          meta: { requestId },
27	        };
28	
29	        // Log 4xx at warn, 5xx at error
30	        if (err.statusCode >= 500) {
31	          logger.error({ err, requestId }, err.message);
32	        } else {
33	          logger.warn({ code: err.code, statusCode: err.statusCode, requestId }, err.message);
34	        }
35	      } else {
36	        // Unexpected error — do not leak internals to the client
37	        ctx.status = 500;
38	        ctx.body = {
39	          error: {
40	            code: 'INTERNAL_ERROR',
41	            message: 'An unexpected error occurred',
42	          },
43	          meta: { requestId },
44	        };
45	        logger.error({ err, requestId }, 'Unhandled error');
46	      }
47	
48	      // Emit the error on the Koa app so koa can handle it in its own error handler
49	      ctx.app.emit('error', err, ctx);
50	    }
51	  };
52	}
