18	function computeComposite(criterionScores, criteriaSchema) {
19	  const criteria = criteriaSchema?.criteria ?? [];
20	  if (!criteria.length) return null;
21	
22	  let weightedSum = 0;
23	  let totalWeight = 0;
24	
25	  for (const criterion of criteria) {
26	    const raw = criterionScores[criterion.id];
27	    if (raw == null) continue;
28	    const normalised = (raw / criterion.maxScore) * 10;
29	    weightedSum += normalised * criterion.weight;
30	    totalWeight += criterion.weight;
31	  }
32	
33	  if (totalWeight === 0) return null;
34	  return Math.round((weightedSum / totalWeight) * 1000) / 1000; // 3 decimal places
35	}
