338	    // and we signal T1 when it should release — no timing guesses needed.
339	    let lockAcquiredResolver, releaseLockResolver;
340	    const lockAcquiredPromise = new Promise((resolve) => { lockAcquiredResolver = resolve; });
341	    const lockReleasedPromise = new Promise((resolve) => { releaseLockResolver = resolve; });
342	
343	    // T1: acquire an explicit FOR UPDATE lock and hold it until signalled
344	    const lockHolder = knex.transaction(async (trx) => {
345	      await trx.raw('SELECT id FROM sessions WHERE token_hash = ? FOR UPDATE', [tokenHash]);
346	      lockAcquiredResolver(); // deterministic signal: lock is now held
347	      await lockReleasedPromise;
348	      // Transaction commits here, releasing the lock
349	    });
350	
351	    // Wait until T1 has actually acquired the lock before we trigger the race
352	    await lockAcquiredPromise;
353	
354	    // Start validateAndRotate — first attempt will hit 55P03, retry after 50 ms
355	    const validatePromise = sessionService.validateAndRotate(rawToken);
356	
357	    // Release the lock promptly — well before the 50 ms retry fires
358	    releaseLockResolver();
359	
360	    const result = await validatePromise;
361	    await lockHolder;
362	
363	    expect(result.user.id).toBe(accountId);
364	
365	    await sessionService.invalidate(rawToken);
366	  });
