24	        'rp.active_assignments',
25	        'rp.expertise_tags',
26	        'rp.created_at',
27	      );
28	
29	    if (filters.available != null) q.where('rp.available', filters.available === 'true');
30	    if (filters.active != null) q.where('rp.active', filters.active === 'true');
31	
32	    const total = await q.clone().count('rp.id as count').first().then((r) => Number(r.count));
