169	
170	  // ── Recommendations ────────────────────────────────────────────────────────
171	
172	  /**
173	   * Generate ranked recommendations with a deterministic explanation for each item.
174	   *
175	   * Scoring rules (applied in order, additive):
176	   *   +N   per view in the last 30 days (N = view count)
177	   *   +3   if bookmarked
178	   *   +2   if entity_type matches a tag subscription
179	   *
180	   * Cold-start: when the user has no signals at all, fall back to the 10 most
181	   * recently published active entities across all entity types.
182	   *
183	   * Each recommendation item includes a `reasons` array explaining the score,
184	   * making the output fully explainable.
185	   *
186	   * @param {string} accountId
187	   * @returns {Array<{entityType, stableId, score, reasons}>}
188	   */
189	  async getRecommendations(accountId) {
190	    const since = new Date();
191	    since.setDate(since.getDate() - 30);
192	
193	    recommendationGenerationsTotal.inc();
194	    const [views, bookmarks, tagSubs] = await Promise.all([
195	      knex('entity_view_history')
196	        .where('account_id', accountId)
197	        .where('viewed_at', '>=', since.toISOString())
198	        .select('entity_type', 'stable_id')
199	        .count('id as view_count')
200	        .groupBy('entity_type', 'stable_id')
201	        .orderBy('view_count', 'desc')
202	        .limit(50),
203	      knex('entity_bookmarks')
204	        .where('account_id', accountId)
205	        .select('entity_type', 'stable_id'),
206	      knex('tag_subscriptions')
207	        .where('account_id', accountId)
208	        .select('tag', 'tag_type'),
209	    ]);
210	
211	    const subscribedEntityTypes = new Set(
212	      tagSubs.filter((t) => t.tag_type === 'entity_type').map((t) => t.tag),
213	    );
214	
215	    // ── Cold-start path ───────────────────────────────────────────────────────
216	    if (!views.length && !bookmarks.length && !tagSubs.length) {
217	      const coldRecs = await this._coldStartRecommendations(accountId);
218	      await this._persistExplanations(accountId, coldRecs);
219	      return coldRecs;
220	    }
221	
222	    // ── Scored path ───────────────────────────────────────────────────────────
223	    const topicTags = new Set(
224	      tagSubs.filter((t) => t.tag_type === 'topic').map((t) => t.tag.toLowerCase()),
225	    );
226	
227	    const scoreMap = new Map();
228	
229	    const getOrCreate = (entityType, stableId) => {
230	      const key = `${entityType}:${stableId}`;
231	      if (!scoreMap.has(key)) {
232	        scoreMap.set(key, { entityType, stableId, score: 0, reasons: [] });
233	      }
234	      return scoreMap.get(key);
235	    };
236	
237	    for (const v of views) {
238	      const count = Number(v.view_count);
239	      const item = getOrCreate(v.entity_type, v.stable_id);
240	      item.score += count;
241	      item.reasons.push({ type: 'frequently_viewed', viewCount: count });
242	    }
243	
244	    for (const b of bookmarks) {
245	      const item = getOrCreate(b.entity_type, b.stable_id);
246	      item.score += 3;
247	      item.reasons.push({ type: 'bookmarked' });
248	    }
249	
250	    // Users with only tag subscriptions and no view/bookmark history produce an empty
251	    // scoreMap at this point. Seed it with popular entities from subscribed types so
252	    // the subscription boost below has something to apply to.
253	    if (subscribedEntityTypes.size > 0 && !scoreMap.size) {
254	      const seedItems = await this._coldStartRecommendations(accountId);
255	      for (const item of seedItems) {
256	        getOrCreate(item.entityType, item.stableId);
257	      }
258	    }
259	
260	    // Apply tag-subscription boost to all already-scored items of matching entity type
261	    for (const item of scoreMap.values()) {
262	      if (subscribedEntityTypes.has(item.entityType)) {
263	        item.score += 2;
264	        item.reasons.push({ type: 'tag_subscription', entityType: item.entityType });
265	      }
266	    }
267	
268	    // Apply tag similarity scoring (Jaccard on topic tags vs. entity name tokens)
269	    if (topicTags.size > 0) {
270	      await this._applyTagSimilarity(scoreMap, topicTags);
271	    }
272	
273	    const recommendations = [...scoreMap.values()]
274	      .sort((a, b) => b.score - a.score)
275	      .slice(0, 10);
276	
277	    await this._persistExplanations(accountId, recommendations);
278	    return recommendations;
279	  },
280	
281	  /**
282	   * Compute Jaccard similarity between user's topic tag subscriptions and entity name/tag tokens.
283	   * Applies an additive score boost (max +5) to each matching entity.
284	   *
285	   * @param {Map} scoreMap  The live score map keyed by "entityType:stableId"
286	   * @param {Set<string>} topicTags  Lowercase topic tags from the user's subscriptions
287	   */
288	  async _applyTagSimilarity(scoreMap, topicTags) {
289	    const ENTITY_TABLES = {
290	      university:             { table: 'university_versions',             idCol: 'university_id' },
291	      school:                 { table: 'school_versions',                 idCol: 'school_id' },
292	      major:                  { table: 'major_versions',                  idCol: 'major_id' },
293	      research_track:         { table: 'research_track_versions',         idCol: 'research_track_id' },
294	      enrollment_plan:        { table: 'enrollment_plan_versions',        idCol: 'enrollment_plan_id' },
295	      transfer_quota:         { table: 'transfer_quota_versions',         idCol: 'transfer_quota_id' },
296	      application_requirement: { table: 'application_requirement_versions', idCol: 'application_requirement_id' },
297	      retest_rule:            { table: 'retest_rule_versions',            idCol: 'retest_rule_id' },
298	    };
299	
300	    // Group items by entity type for batched DB fetches
301	    const byType = new Map();
302	    for (const [key, item] of scoreMap) {
303	      if (!byType.has(item.entityType)) byType.set(item.entityType, []);
304	      byType.get(item.entityType).push({ key, stableId: item.stableId });
305	    }
306	
307	    for (const [entityType, items] of byType) {
308	      const cfg = ENTITY_TABLES[entityType];
309	      if (!cfg) continue;
310	      const stableIds = items.map((i) => i.stableId);
311	      const rows = await knex(cfg.table)
312	        .whereIn(cfg.idCol, stableIds)
313	        .where('lifecycle_status', 'active')
314	        .select(
315	          knex.raw(`${cfg.idCol} AS stable_id`),
316	          knex.raw(`payload_json->>'name' AS name`),
317	          knex.raw(`payload_json->>'tags' AS tags`),
318	        );
319	
320	      const entityData = new Map(rows.map((r) => [r.stable_id, r]));
321	      for (const { key, stableId } of items) {
322	        const data = entityData.get(stableId);
323	        if (!data) continue;
324	
325	        // Entity token set = name words + explicit tag array from payload
326	        const nameTokens = (data.name || '').toLowerCase().split(/\s+/).filter(Boolean);
327	        let payloadTags = [];
328	        try { payloadTags = data.tags ? JSON.parse(data.tags) : []; } catch { /* ignore */ }
329	        const entitySet = new Set([...nameTokens, ...payloadTags.map((t) => String(t).toLowerCase())]);
330	
331	        // Jaccard(topicTags, entitySet)
332	        const intersection = [...topicTags].filter((t) => entitySet.has(t)).length;
333	        const union = new Set([...topicTags, ...entitySet]).size;
334	        const similarity = union > 0 ? intersection / union : 0;
335	
336	        if (similarity > 0) {
337	          const item = scoreMap.get(key);
338	          const boost = Math.round(similarity * 5); // max +5 for perfect overlap
339	          item.score += boost;
340	          item.reasons.push({ type: 'tag_similarity', similarity: Math.round(similarity * 100) / 100 });
341	        }
342	      }
343	    }
344	  },
345	
346	  /**
347	   * Persist recommendation explanations for auditability.
348	   * Fire-and-forget (non-blocking) — never surfaces errors to the caller.
349	   */
350	  async _persistExplanations(accountId, recommendations) {
351	    if (!recommendations.length) return;
352	    const now = new Date().toISOString();
353	    const rows = recommendations.map((r) => ({
354	      account_id: accountId,
355	      entity_type: r.entityType,
356	      stable_id: r.stableId,
357	      score: r.score,
358	      reasons: JSON.stringify(r.reasons),
359	      generated_at: now,
360	    }));
361	    knex('recommendation_explanations').insert(rows).catch(() => {});
362	  },
363	
364	  /**
365	   * Cold-start fallback: return up to 10 recommended active entities.
366	   *
367	   * Signal priority:
368	   *   1. Declared interests — entity_type tag subscriptions narrow the candidate pool.
369	   *   2. Popularity         — global view count in the last 30 days ranks candidates.
370	   *   3. Recency            — tie-breaks by published_at DESC.
371	   *
372	   * Used when a user has no view history, bookmarks, or tag subscriptions of their own.
373	   */
374	  async _coldStartRecommendations(accountId) {
375	    const ENTITY_VERSION_TABLES = [
376	      { table: 'university_versions',            entityType: 'university',            idCol: 'university_id' },
377	      { table: 'school_versions',                entityType: 'school',                idCol: 'school_id' },
378	      { table: 'major_versions',                 entityType: 'major',                 idCol: 'major_id' },
379	      { table: 'research_track_versions',        entityType: 'research_track',        idCol: 'research_track_id' },
380	      { table: 'enrollment_plan_versions',       entityType: 'enrollment_plan',       idCol: 'enrollment_plan_id' },
381	      { table: 'transfer_quota_versions',        entityType: 'transfer_quota',        idCol: 'transfer_quota_id' },
382	      { table: 'application_requirement_versions', entityType: 'application_requirement', idCol: 'application_requirement_id' },
383	      { table: 'retest_rule_versions',           entityType: 'retest_rule',           idCol: 'retest_rule_id' },
384	    ];
385	
386	    // Check declared-interest entity_type tag subscriptions
387	    const subscribedTypes = await knex('tag_subscriptions')
388	      .where({ account_id: accountId, tag_type: 'entity_type' })
389	      .pluck('tag');
390	
391	    const targetTables = subscribedTypes.length > 0
392	      ? ENTITY_VERSION_TABLES.filter((e) => subscribedTypes.includes(e.entityType))
393	      : ENTITY_VERSION_TABLES;
394	
395	    const since = new Date();
396	    since.setDate(since.getDate() - 30);
397	
398	    // Global popularity: total view count per entity in the last 30 days
399	    const popularity = await knex('entity_view_history')
400	      .select('entity_type', 'stable_id')
401	      .count('id as view_count')
402	      .where('viewed_at', '>=', since.toISOString())
403	      .groupBy('entity_type', 'stable_id');
404	
405	    const popularityMap = new Map(
406	      popularity.map((r) => [`${r.entity_type}:${r.stable_id}`, Number(r.view_count)]),
407	    );
408	
409	    const parts = await Promise.all(
410	      targetTables.map(({ table, entityType, idCol }) =>
411	        knex(table)
412	          .where('lifecycle_status', 'active')
