27	  return async function idempotency(ctx, next) {
28	    const idempotencyKey = ctx.get('Idempotency-Key');
29	
30	    // Skip non-write methods entirely
31	    if (!IDEMPOTENT_METHODS.has(ctx.method)) {
32	      await next();
33	      return;
34	    }
35	
36	    // Unauthenticated write requests (e.g. POST /v1/auth/login) bypass idempotency
37	    const accountId = ctx.state.user?.id;
38	    if (!accountId) {
39	      await next();
40	      return;
41	    }
42	
43	    // Authenticated write requests MUST supply an Idempotency-Key
44	    if (!idempotencyKey) {
45	      ctx.status = 400;
46	      ctx.body = {
47	        error: {
48	          code: 'MISSING_IDEMPOTENCY_KEY',
49	          message: 'Idempotency-Key header is required for authenticated write operations',
50	        },
51	        meta: { requestId: ctx.state.requestId },
52	      };
53	      return;
54	    }
55	
56	    const fingerprint = requestFingerprint(ctx.method, ctx.path, ctx.request.body || {});
57	
58	    // Attempt to atomically reserve the slot before running the handler.
59	    // If reserve returns false, a record already exists for this (account, key).
60	    const reserved = await idempotencyRepository.reserve(accountId, idempotencyKey, fingerprint);
61	
62	    if (!reserved) {
63	      // Slot already existed — look up the record to decide what to return
64	      const existing = await idempotencyRepository.findByAccountAndKey(accountId, idempotencyKey);
65	
66	      if (!existing) {
67	        // Record existed when we tried to insert but has since expired — treat as new
68	        // Re-attempt the reserve; if it fails again another request is truly concurrent
69	        const retried = await idempotencyRepository.reserve(accountId, idempotencyKey, fingerprint);
70	        if (!retried) {
71	          ctx.status = 409;
72	          ctx.body = {
73	            error: {
74	              code: 'IDEMPOTENCY_KEY_IN_FLIGHT',
75	              message: 'A request with this Idempotency-Key is already being processed',
