13	      .where({ account_id: accountId })
14	      .orderBy('updated_at', 'desc');
15	    if (options.subscribed != null) q.where('subscribed', options.subscribed === 'true');
16	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
17	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
18	    return { rows, total };
19	  },
