21	  async create({ accountId, name, queryText, filters = {}, subscribed = false }) {
22	    try {
23	      const [sq] = await knex('search_saved_queries')
24	        .insert({ account_id: accountId, name, query_text: queryText, filters: JSON.stringify(filters), subscribed })
25	        .returning('*');
