83	    if (!sq) throw new NotFoundError('Saved query not found');
84	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
85	
86	    const result = await searchService.search(sq.query_text, {
87	      entityTypes: sq.filters?.entityTypes,
88	      lifecycleStatus: sq.filters?.lifecycleStatus,
89	      effectiveFrom: sq.filters?.effectiveFrom,
90	      effectiveTo: sq.filters?.effectiveTo,
91	      nameContains: sq.filters?.nameContains,
92	      descriptionContains: sq.filters?.descriptionContains,
93	      tags: sq.filters?.tags,
94	      accountId,
95	    });
96	
97	    await knex('search_saved_queries').where({ id }).update({
98	      last_run_at: new Date().toISOString(),
99	      last_result_count: result.total,
100	      updated_at: new Date().toISOString(),
101	    });
102	
