1	import knex from '../../common/db/knex.js';
2	import { NotFoundError, ConflictError } from '../../common/errors/AppError.js';
3	import config from '../../config/env.js';
4	import { recommendationGenerationsTotal } from '../../common/metrics/metrics.js';
5	import { auditService } from '../admin/audit/audit.service.js';
6	import logger from '../../common/logging/logger.js';
7	
8	const RETENTION_DAYS = config.personalization.historyRetentionDays;
9	
10	export const personalizationService = {
11	  // ── View history ───────────────────────────────────────────────────────────
12	
13	  async recordView({ accountId, entityType, stableId, versionId }) {
14	    await knex('entity_view_history').insert({
15	      account_id: accountId,
16	      entity_type: entityType,
17	      stable_id: stableId,
18	      version_id: versionId || null,
19	    });
20	    auditService.record({
21	      actorAccountId: accountId,
22	      actionType: 'personalization.view_recorded',
23	      entityType,
24	      entityId: stableId,
25	      afterSummary: { entityType, versionId: versionId || null },
26	    }).catch((err) => logger.warn({ err }, 'audit write failed'));
27	  },
28	
29	  async getHistory(accountId, options = {}) {
30	    const pageSize = Math.min(options.pageSize || 20, 100);
31	    const page = options.page || 1;
32	    const since = new Date();
33	    since.setDate(since.getDate() - RETENTION_DAYS);
34	    const q = knex('entity_view_history')
35	      .where('account_id', accountId)
36	      .where('viewed_at', '>=', since.toISOString())
37	      .orderBy('viewed_at', 'desc');
38	    if (options.entityType) q.where('entity_type', options.entityType);
39	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
40	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
41	    return { rows, total };
42	  },
43	
44	  // ── Bookmarks ──────────────────────────────────────────────────────────────
45	
46	  async addBookmark({ accountId, entityType, stableId }) {
47	    try {
48	      const [bookmark] = await knex('entity_bookmarks')
49	        .insert({ account_id: accountId, entity_type: entityType, stable_id: stableId })
50	        .returning('*');
51	      auditService.record({
52	        actorAccountId: accountId,
53	        actionType: 'personalization.bookmark_added',
54	        entityType,
55	        entityId: stableId,
56	        afterSummary: { entityType },
57	      }).catch((err) => logger.warn({ err }, 'audit write failed'));
58	      return bookmark;
59	    } catch (err) {
60	      if (err.code === '23505') throw new ConflictError('Already bookmarked');
61	      throw err;
62	    }
63	  },
64	
65	  async removeBookmark({ accountId, entityType, stableId }) {
66	    const deleted = await knex('entity_bookmarks')
67	      .where({ account_id: accountId, entity_type: entityType, stable_id: stableId })
68	      .delete();
69	    if (!deleted) throw new NotFoundError('Bookmark not found');
70	    auditService.record({
71	      actorAccountId: accountId,
72	      actionType: 'personalization.bookmark_removed',
73	      entityType,
74	      entityId: stableId,
75	      beforeSummary: { entityType },
76	    }).catch((err) => logger.warn({ err }, 'audit write failed'));
77	  },
78	
79	  async getBookmarks(accountId, options = {}) {
80	    const pageSize = Math.min(options.pageSize || 20, 100);
81	    const page = options.page || 1;
82	    const q = knex('entity_bookmarks').where('account_id', accountId).orderBy('created_at', 'desc');
83	    if (options.entityType) q.where('entity_type', options.entityType);
84	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
85	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
86	    return { rows, total };
87	  },
88	
89	  // ── Preferences ────────────────────────────────────────────────────────────
90	
91	  async getPreferences(accountId) {
92	    const rows = await knex('user_preferences').where('account_id', accountId);
93	    // Return as a flat key→value map
94	    return Object.fromEntries(rows.map((r) => [r.pref_key, r.pref_value]));
95	  },
96	
97	  async setPreference(accountId, prefKey, prefValue) {
98	    const [pref] = await knex('user_preferences')
99	      .insert({
100	        account_id: accountId,
101	        pref_key: prefKey,
102	        pref_value: JSON.stringify(prefValue),
103	        updated_at: new Date().toISOString(),
104	      })
105	      .onConflict(['account_id', 'pref_key'])
106	      .merge(['pref_value', 'updated_at'])
107	      .returning('*');
108	    auditService.record({
109	      actorAccountId: accountId,
110	      actionType: 'personalization.preference_set',
111	      entityType: 'preference',
112	      entityId: accountId,
113	      afterSummary: { prefKey },
114	    }).catch((err) => logger.warn({ err }, 'audit write failed'));
115	    return pref;
116	  },
117	
118	  async deletePreference(accountId, prefKey) {
119	    const deleted = await knex('user_preferences')
120	      .where({ account_id: accountId, pref_key: prefKey })
121	      .delete();
122	    if (!deleted) throw new NotFoundError('Preference not found');
123	    auditService.record({
124	      actorAccountId: accountId,
125	      actionType: 'personalization.preference_deleted',
126	      entityType: 'preference',
127	      entityId: accountId,
128	      beforeSummary: { prefKey },
129	    }).catch((err) => logger.warn({ err }, 'audit write failed'));
130	  },

130	  },
131	
132	  // ── Tag subscriptions ──────────────────────────────────────────────────────
133	
134	  async getTagSubscriptions(accountId) {
135	    return knex('tag_subscriptions').where('account_id', accountId).orderBy('created_at', 'desc');
136	  },
137	
138	  async addTagSubscription({ accountId, tag, tagType = 'topic' }) {
139	    try {
140	      const [sub] = await knex('tag_subscriptions')
141	        .insert({ account_id: accountId, tag, tag_type: tagType })
142	        .returning('*');
143	      auditService.record({
144	        actorAccountId: accountId,
145	        actionType: 'personalization.tag_subscribed',
146	        entityType: 'tag_subscription',
147	        entityId: accountId,
148	        afterSummary: { tag, tagType },
149	      }).catch((err) => logger.warn({ err }, 'audit write failed'));
150	      return sub;
151	    } catch (err) {
152	      if (err.code === '23505') throw new ConflictError('Already subscribed to this tag');
153	      throw err;
154	    }
155	  },
156	
157	  async removeTagSubscription({ accountId, tag }) {
158	    const deleted = await knex('tag_subscriptions')
159	      .where({ account_id: accountId, tag })
160	      .delete();
161	    if (!deleted) throw new NotFoundError('Tag subscription not found');
162	    auditService.record({
163	      actorAccountId: accountId,
164	      actionType: 'personalization.tag_unsubscribed',
165	      entityType: 'tag_subscription',
166	      entityId: accountId,
167	      beforeSummary: { tag },
168	    }).catch((err) => logger.warn({ err }, 'audit write failed'));
169	  },

