1	import { randomBytes, createHash } from 'crypto';
2	
3	/**
4	 * Generates a cryptographically random opaque session token.
5	 * Returns a 64-character hex string (256 bits of entropy).
6	 * Never use UUID for session tokens — insufficient entropy.
7	 */
8	export function generateOpaqueToken() {
9	  return randomBytes(32).toString('hex');
10	}
11	
12	/**
13	 * Hashes a raw token with SHA-256 for database storage.
14	 * The raw token is never stored; only the hash.
15	 * @param {string} rawToken  The 64-char hex token returned by generateOpaqueToken()
16	 * @returns {Buffer}  32-byte Buffer (suitable for BYTEA column)
17	 */
18	export function hashToken(rawToken) {
19	  return createHash('sha256').update(rawToken, 'utf8').digest();
20	}
21	
22	/**
23	 * Computes SHA-256 of a Buffer or string.
24	 * Used for attachment fingerprinting and idempotency key fingerprinting.
25	 * @param {Buffer|string} data
26	 * @returns {string}  64-char hex digest
27	 */
28	export function sha256Hex(data) {
29	  return createHash('sha256').update(data).digest('hex');
30	}
31	
32	/**
33	 * Recursively sorts all object keys so that JSON serialisation is canonical.
34	 * Arrays preserve order; object keys are sorted alphabetically.
35	 */
36	function deepSortKeys(value) {
37	  if (Array.isArray(value)) return value.map(deepSortKeys);
38	  if (value !== null && typeof value === 'object') {
39	    return Object.fromEntries(
40	      Object.keys(value).sort().map((k) => [k, deepSortKeys(value[k])]),
41	    );
42	  }
43	  return value;
44	}
45	
46	/**
47	 * Generates a request fingerprint for idempotency key deduplication.
48	 * Canonical form: deep-sorted JSON of { method, path, body } ensures that
49	 * two requests with the same semantics always produce the same fingerprint,
50	 * and that different methods/paths/bodies never collide.
51	 *
52	 * @param {string} method  HTTP method (normalised to uppercase)
53	 * @param {string} path    Request path
54	 * @param {object} body    Request body object
55	 * @returns {string}  64-char hex digest
56	 */
57	export function requestFingerprint(method, path, body) {
58	  const canonical = deepSortKeys({ method: method.toUpperCase(), path, body: body ?? null });
59	  return sha256Hex(JSON.stringify(canonical));
60	}
