17	export const attachmentService = {
18	  /**
19	   * Upload a file attachment for a review assignment.
20	   *
21	   * @param {object} params
22	   * @param {string} params.assignmentId
23	   * @param {object} params.file  koa-body file object { filepath, originalFilename, mimetype, size }
24	   * @param {string} actorId
25	   * @param {string} requestId
26	   */
27	  async upload({ assignmentId, file }, actorId, requestId) {
28	    // Validate declared MIME type against allow-list
29	    if (
30	      storageConfig.allowedMimeTypes.length > 0 &&
31	      !storageConfig.allowedMimeTypes.includes(file.mimetype)
32	    ) {
33	      attachmentUploadFailuresTotal.inc({ reason: 'disallowed_mime' });
34	      throw new UnprocessableError(`File type ${file.mimetype} is not allowed`);
35	    }
36	
37	    // Validate file size (koa-body already enforces maxFileSize, this is belt-and-suspenders)
38	    if (file.size > storageConfig.maxFileBytes) {
39	      attachmentUploadFailuresTotal.inc({ reason: 'oversized' });
40	      throw new UnprocessableError(
41	        `File exceeds maximum size of ${storageConfig.maxFileBytes} bytes`,
42	      );
43	    }
44	
45	    // Load assignment and check reviewer ownership
46	    const assignment = await knex('review_assignments').where({ id: assignmentId }).first();
47	    if (!assignment) throw new NotFoundError('Assignment not found');
48	
49	    const reviewerProfile = await knex('reviewer_profiles')
50	      .where({ account_id: actorId })
51	      .first('id');
52	    const isAdmin = false; // Enforced upstream by RBAC
53	    if (!reviewerProfile || assignment.reviewer_id !== reviewerProfile.id) {
54	      throw new AuthorizationError('You are not assigned to this review');
55	    }
56	
57	    // Enforce per-review attachment limit
58	    const existing = await knex('review_attachments')
59	      .where({ assignment_id: assignmentId })
60	      .count('id as count')
61	      .first()
62	      .then((r) => Number(r.count));
63	    if (existing >= storageConfig.maxFilesPerReview) {
64	      throw new UnprocessableError(
65	        `Maximum of ${storageConfig.maxFilesPerReview} attachments per review`,
66	      );
67	    }
68	
69	    // Compute SHA-256 and verify magic bytes (prevents MIME-type spoofing)
70	    const fileBuffer = await fs.readFile(file.filepath);
71	    const detectedType = await fileTypeFromBuffer(fileBuffer);
72	    if (!detectedType || detectedType.mime !== file.mimetype) {
73	      attachmentUploadFailuresTotal.inc({ reason: 'magic_byte_mismatch' });
74	      throw new UnprocessableError(
75	        `File signature does not match declared type ${file.mimetype}`,
76	      );
77	    }
78	    const contentHash = createHash('sha256').update(fileBuffer).digest('hex');
79	
80	    // Determine storage path — partitioned by assignment ID to avoid filesystem hotspots
81	    const ext = storageConfig.mimeToExt[file.mimetype] ?? path.extname(file.originalFilename) ?? '';
82	    const storagePath = path.join(
83	      assignmentId.substring(0, 2),
84	      assignmentId.substring(2, 4),
85	      `${assignmentId}_${contentHash}${ext}`,
86	    );
87	    const absolutePath = path.join(storageConfig.attachmentsRoot, storagePath);
88	
89	    // Ensure directory exists
90	    await fs.mkdir(path.dirname(absolutePath), { recursive: true });
91	
92	    // Write file to storage
93	    await fs.copyFile(file.filepath, absolutePath);
94	    // Clean up temp file
95	    await fs.unlink(file.filepath).catch(() => {});
96	
97	    return withTransaction(async (trx) => {
98	      const [attachment] = await trx('review_attachments')
99	        .insert({
100	          assignment_id: assignmentId,
101	          uploaded_by: actorId,
102	          original_filename: file.originalFilename,
103	          storage_path: storagePath,
104	          mime_type: file.mimetype,
105	          file_size_bytes: file.size,
106	          content_hash: contentHash,
107	          virus_scan_status: 'pending',
108	        })
109	        .onConflict(['assignment_id', 'content_hash'])
110	        .ignore()
111	        .returning('*');
112	
113	      if (!attachment) {
114	        throw new UnprocessableError('This file has already been uploaded for this assignment');
115	      }
116	
117	      await auditService.record({
118	        actorAccountId: actorId,
119	        actionType: 'attachment.uploaded',
120	        entityType: 'review_attachment',
121	        entityId: attachment.id,
122	        requestId,
123	        afterSummary: {
124	          assignmentId,
125	          filename: file.originalFilename,
126	          mimeType: file.mimetype,
127	          sizeBytes: file.size,
128	        },
129	      }, trx);
130	
131	      return attachment;
132	    });
133	  },
