135	  async listByAssignment(assignmentId, viewer) {
136	    const assignment = await knex('review_assignments').where({ id: assignmentId }).first();
137	    if (!assignment) throw new NotFoundError('Assignment not found');
138	
139	    const isAdmin =
140	      viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
141	    if (!isAdmin) {
142	      const reviewerProfile = await knex('reviewer_profiles')
143	        .where({ account_id: viewer.id })
144	        .first('id');
145	      if (!reviewerProfile || assignment.reviewer_id !== reviewerProfile.id) {
146	        throw new NotFoundError('Assignment not found');
147	      }
148	    }
