156	  async delete(attachmentId, viewer, requestId) {
157	    const actorId = viewer.id;
158	    const attachment = await knex('review_attachments').where({ id: attachmentId }).first();
159	    if (!attachment) throw new NotFoundError('Attachment not found');
160	
161	    // Uploader can always delete their own attachment.
162	    // SYSTEM_ADMIN and PROGRAM_ADMIN can delete any attachment for operational remediation.
163	    const isAdmin =
164	      viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
165	    if (attachment.uploaded_by !== actorId && !isAdmin) {
166	      throw new AuthorizationError('You can only delete your own attachments');
167	    }
168	
169	    await withTransaction(async (trx) => {
170	      await trx('review_attachments').where({ id: attachmentId }).delete();
171	      await auditService.record({
172	        actorAccountId: actorId,
173	        actionType: 'attachment.deleted',
174	        entityType: 'review_attachment',
175	        entityId: attachmentId,
176	        requestId,
177	        beforeSummary: { filename: attachment.original_filename },
178	      }, trx);
179	    });
180	
181	    // Remove from filesystem (best effort)
182	    const absolutePath = path.join(storageConfig.attachmentsRoot, attachment.storage_path);
183	    await fs.unlink(absolutePath).catch(() => {});
184	  },
185	};
