9	/**
10	 * Fisher-Yates shuffle using crypto.getRandomValues() for cryptographic randomness.
11	 * Required for blind review integrity.
12	 */
13	function secureShuffle(array) {
14	  const arr = [...array];
15	  for (let i = arr.length - 1; i > 0; i--) {
16	    const bytes = randomBytes(4);
17	    const j = Math.floor((bytes.readUInt32BE(0) / 0xFFFFFFFF) * (i + 1));
18	    [arr[i], arr[j]] = [arr[j], arr[i]];
19	  }
20	  return arr;
21	}
22	
23	export const assignmentService = {
24	  /**
25	   * Create a single assignment (manual or direct).
26	   */
27	  async create({ applicationId, reviewerId, cycleId, mode, blindMode, assignedBy, dueAt }, requestId) {
28	    // Validate application and reviewer exist
29	    const [app, reviewer] = await Promise.all([
30	      knex('applications').where({ id: applicationId }).first(),
31	      knex('reviewer_profiles').where({ id: reviewerId }).first(),
32	    ]);
33	    if (!app) throw new NotFoundError('Application not found');
34	    if (!reviewer) throw new NotFoundError('Reviewer not found');
35	    if (!reviewer.active || !reviewer.available) {
36	      throw new UnprocessableError('Reviewer is not available for assignment');
37	    }
38	
39	    // Derive cycle_id from the application record — never trust the client value
40	    const resolvedCycleId = app.cycle_id;
41	    if (!resolvedCycleId) throw new UnprocessableError('Application is not associated with a review cycle');
42	    if (cycleId && cycleId !== resolvedCycleId) {
43	      throw new UnprocessableError(
44	        'Supplied cycleId does not match the application\'s review cycle',
45	      );
46	    }
47	
48	    const { hasConflict, reasons } = await coiService.checkConflict(reviewerId, applicationId);
49	    await coiService.recordCheck({
50	      reviewerId, applicationId, hasConflict, reasons, checkedBy: assignedBy,
51	    });
52	
53	    if (hasConflict) {
54	      throw new UnprocessableError(
55	        'Assignment blocked due to conflict of interest',
56	        reasons.map((r) => ({ field: 'reviewer', issue: r.detail })),
57	      );
58	    }
59	
60	    return withTransaction(async (trx) => {
61	      const [assignment] = await trx('review_assignments')
62	        .insert({
63	          application_id: applicationId,
64	          reviewer_id: reviewerId,
65	          cycle_id: resolvedCycleId,
66	          assignment_mode: mode || 'manual',
67	          blind_mode: blindMode || 'blind',
68	          assigned_by: assignedBy,
69	          due_at: dueAt || null,
70	        })
71	        .returning('*');
72	
73	      // Update reviewer load counter
74	      await trx('reviewer_profiles')
75	        .where({ id: reviewerId })
76	        .increment('active_assignments', 1);
77	
78	      await auditService.record({
79	        actorAccountId: assignedBy,
80	        actionType: 'review_assignment.created',
81	        entityType: 'review_assignment',
82	        entityId: assignment.id,
83	        requestId,
84	        afterSummary: { applicationId, reviewerId, mode: assignment.assignment_mode },
85	      }, trx);
86	
87	      return assignment;
88	    });
89	  },
90	
91	  /**
92	   * Batch assignment — randomly or by rules.
93	   * Assigns the minimum required number of reviewers to each application,
94	   * filtered by COI and load balance.
95	   *
96	   * @param {object} params
97	   * @param {string[]} params.applicationIds
98	   * @param {string} params.cycleId
99	   * @param {string} params.mode  'random' | 'rule_based'
100	   * @param {string} params.blindMode
101	   * @param {number} params.reviewersPerApplication
102	   * @param {string} params.assignedBy  Actor account ID
103	   */
104	  async batchAssign({ applicationIds, cycleId, mode, blindMode, reviewersPerApplication, assignedBy }, requestId) {
105	    const minReviewers = reviewersPerApplication || reviewPolicies.assignment.minReviewersPerApplication;
106	
107	    // Load all applications to derive cycle_id server-side
108	    const applications = await knex('applications')
109	      .whereIn('id', applicationIds)
110	      .select('id', 'cycle_id');
111	
112	    const foundIds = new Set(applications.map((a) => a.id));
113	    const missing = applicationIds.filter((id) => !foundIds.has(id));
114	    if (missing.length) throw new NotFoundError(`Applications not found: ${missing.join(', ')}`);
115	
116	    // Build per-application cycle_id map and validate all belong to the same cycle
117	    const appCycleMap = new Map(applications.map((a) => [a.id, a.cycle_id]));
118	    const distinctCycles = new Set(applications.map((a) => a.cycle_id).filter(Boolean));
119	    if (distinctCycles.size === 0) throw new UnprocessableError('Applications are not associated with any review cycle');
120	    if (distinctCycles.size > 1) {
121	      throw new UnprocessableError('All applications in a batch must belong to the same review cycle');
122	    }
123	    const resolvedCycleId = [...distinctCycles][0];
124	
125	    // If client supplied cycleId, validate it matches
126	    if (cycleId && cycleId !== resolvedCycleId) {
127	      throw new UnprocessableError(
128	        'Supplied cycleId does not match the applications\' review cycle',
129	      );
130	    }
131	
132	    // Load eligible reviewers
133	    const eligibleReviewers = await knex('reviewer_profiles')
134	      .where({ available: true, active: true })
135	      .whereRaw('active_assignments < max_load')
136	      .select('id', 'expertise_tags', 'max_load', 'active_assignments');
137	
138	    if (eligibleReviewers.length === 0) {
139	      throw new UnprocessableError('No eligible reviewers available for assignment');
140	    }
141	
142	    // ── Rule-based: rank reviewers by expertise match per application ─────────
143	    // ── Random: shuffle pool once and apply uniformly ─────────────────────────
144	    let reviewerOrderByApp = null; // Map<appId, reviewer[]> — only set for rule_based
145	
146	    if (mode === 'rule_based') {
147	      // Load the program choices (major→field) for each application so we can
148	      // match against reviewer expertise_tags.
149	      const programRows = await knex('application_program_choices as apc')
150	        .join('major_versions as mv', function () {
151	          this.on('mv.major_id', '=', 'apc.major_id').andOn(
152	            'mv.lifecycle_status', '=', knex.raw("'active'"),
153	          );
154	        })
155	        .whereIn('apc.application_id', applicationIds)
156	        .select(
157	          'apc.application_id',
158	          knex.raw("LOWER(mv.payload_json->>'name') AS program_name"),
159	          knex.raw("LOWER(mv.payload_json->>'field') AS program_field"),
160	        );
161	
162	      // Build per-application keyword set
163	      const appKeywords = new Map(applicationIds.map((id) => [id, new Set()]));
164	      for (const row of programRows) {
165	        const kw = appKeywords.get(row.application_id);
166	        if (kw) {
167	          if (row.program_name) kw.add(row.program_name);
168	          if (row.program_field) kw.add(row.program_field);
169	        }
170	      }
171	
172	      // Score reviewers per application
173	      reviewerOrderByApp = new Map();
174	      for (const appId of applicationIds) {
175	        const keywords = appKeywords.get(appId) || new Set();
176	        const scored = eligibleReviewers.map((r) => {
177	          const tags = (r.expertise_tags || []).map((t) => String(t).toLowerCase());
178	          const matchCount = tags.filter((t) => keywords.has(t)).length;
179	          // Secondary sort: prefer reviewers with more available capacity
180	          const capacity = r.max_load - r.active_assignments;
181	          return { reviewer: r, matchCount, capacity };
182	        });
183	        // Sort: most expertise matches first, then most available capacity
184	        scored.sort((a, b) => b.matchCount - a.matchCount || b.capacity - a.capacity);
185	        reviewerOrderByApp.set(appId, scored.map((s) => s.reviewer));
186	      }
187	    }
188	
189	    const shuffledReviewers = secureShuffle(eligibleReviewers);
190	
191	    // Build candidate pairs for batch COI check
192	    const candidatePairs = [];
193	    for (const appId of applicationIds) {
194	      const reviewerList = reviewerOrderByApp ? reviewerOrderByApp.get(appId) : shuffledReviewers;
195	      for (const reviewer of (reviewerList || shuffledReviewers)) {
196	        candidatePairs.push({ reviewerId: reviewer.id, applicationId: appId });
197	      }
198	    }
199	
200	    // Batch COI check — returns set of conflicted pairs
201	    const conflictedPairs = await coiService.batchCheck(candidatePairs);
202	
203	    // Filter valid assignments per application.
204	    // reservedCounts tracks how many assignments have been planned for each reviewer
205	    // within this batch so we don't exceed max_load across multiple applications.
206	    const assignments = [];
207	    const errors = [];
208	    const reservedCounts = new Map();
209	
210	    for (const appId of applicationIds) {
211	      const orderedReviewers = reviewerOrderByApp
212	        ? (reviewerOrderByApp.get(appId) || shuffledReviewers)
213	        : shuffledReviewers;
214	
215	      const validReviewers = orderedReviewers.filter(
216	        (r) =>
217	          !conflictedPairs.has(`${r.id}:${appId}`) &&
218	          r.active_assignments + (reservedCounts.get(r.id) || 0) < r.max_load,
219	      );
220	
221	      if (validReviewers.length < minReviewers) {
222	        errors.push({ applicationId: appId, issue: 'Insufficient eligible reviewers after COI filtering' });
223	        continue;
224	      }
225	
226	      for (const reviewer of validReviewers.slice(0, minReviewers)) {
227	        assignments.push({
228	          application_id: appId,
229	          reviewer_id: reviewer.id,
230	          cycle_id: appCycleMap.get(appId) || resolvedCycleId,
231	          assignment_mode: mode || 'random',
232	          blind_mode: blindMode || 'blind',
233	          assigned_by: assignedBy,
234	        });
235	        // Reserve capacity so subsequent applications in this batch see the updated load
236	        reservedCounts.set(reviewer.id, (reservedCounts.get(reviewer.id) || 0) + 1);
237	      }
238	    }
239	
240	    if (assignments.length === 0) {
241	      throw new UnprocessableError('No valid assignments could be created', errors);
242	    }
243	
244	    return withTransaction(async (trx) => {
245	      const created = await trx('review_assignments')
246	        .insert(assignments)
247	        .onConflict(['application_id', 'reviewer_id', 'cycle_id'])
248	        .ignore()
249	        .returning('*');
250	
251	      // Update reviewer load counters
252	      const reviewerCounts = {};
253	      for (const a of created) {
254	        reviewerCounts[a.reviewer_id] = (reviewerCounts[a.reviewer_id] || 0) + 1;
255	      }
256	      for (const [reviewerId, count] of Object.entries(reviewerCounts)) {
257	        await trx('reviewer_profiles')
258	          .where({ id: reviewerId })
259	          .increment('active_assignments', count);
260	      }
261	
262	      await auditService.record({
263	        actorAccountId: assignedBy,
264	        actionType: 'review_assignment.batch_created',
265	        entityType: 'review_assignment',
266	        entityId: resolvedCycleId,
267	        requestId,
268	        afterSummary: { count: created.length, mode, errors: errors.length },
269	      }, trx);
270	
271	      return { created, errors };
272	    });
273	  },
274	
275	  async getById(assignmentId, viewer) {
276	    const assignment = await knex('review_assignments').where({ id: assignmentId }).first();
277	    if (!assignment) throw new NotFoundError('Assignment not found');
278	
279	    // Object-level check: reviewers can only see their own assignments
280	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
281	    if (!isAdmin) {
282	      const reviewerProfile = await knex('reviewer_profiles')
283	        .where({ account_id: viewer.id })
284	        .first('id');
285	      if (!reviewerProfile || assignment.reviewer_id !== reviewerProfile.id) {
