293	  async list(filters, viewer) {
294	    const isAdmin = viewer.roles?.includes('SYSTEM_ADMIN') || viewer.roles?.includes('PROGRAM_ADMIN');
295	    let q = knex('review_assignments').orderBy('assigned_at', 'desc');
296	
297	    if (!isAdmin) {
298	      const reviewerProfile = await knex('reviewer_profiles')
299	        .where({ account_id: viewer.id })
300	        .first('id');
301	      if (!reviewerProfile) return { rows: [], total: 0 };
302	      q = q.where('reviewer_id', reviewerProfile.id);
303	    }
304	
305	    if (filters.cycleId) q = q.where('cycle_id', filters.cycleId);
306	    if (filters.status) q = q.where('status', filters.status);
307	
308	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
309	    const page = Number(filters.page) || 1;
310	    const pageSize = Math.min(Number(filters.pageSize) || 20, 100);
311	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
312	
313	    return { rows, total };
314	  },
315	};
