1	import { describe, it, expect, beforeAll, afterAll } from 'vitest';
2	
3	/**
4	 * Integration tests for scoringService against a real PostgreSQL database.
5	 *
6	 * tests/unit/scoring.composite.spec.js is formula-focused and mocks knex entirely,
7	 * so it cannot catch regressions in the multi-table write path.  These tests
8	 * cover the paths that require a real DB:
9	 *
10	 * submit (happy path):
11	 *   - review_scores persisted with is_draft = false and computed composite_score
12	 *   - review_assignments status transitions to 'submitted'
13	 *   - reviewer_profiles.active_assignments decremented
14	 *
15	 * submit (error paths):
16	 *   - missing required criterion → 422 with per-field details
17	 *   - wrong reviewer → 403
18	 *   - assignment not in submittable state → 422
19	 *   - missing recommendation → 422
20	 *
21	 * saveDraft (upsert behaviour):
22	 *   - first call creates the score row with is_draft = true
23	 *   - second call updates the same row (onConflict merge), no duplicate created
24	 *   - wrong reviewer → 403
25	 *
26	 * Requires a real PostgreSQL test database (graddb_test).
27	 * Run with: npm run test:integration
28	 */
29	
30	const DUMMY_HASH = '$2b$12$LQv3c1yqBWVHxkd0LHAkCOYz6TtxMQJqhN8/NRhE6nJhbZgJkSta2';
31	const TS = Date.now();
32	
33	let knex;
34	let scoringService;
35	
36	// Shared fixtures created in beforeAll
37	let cycleId;
38	let templateId;
39	let applicationId;
40	let reviewerAccountId;
41	let reviewerProfileId;
42	let otherReviewerAccountId;
43	let assignmentId;
