45	// Used by submit tests that transition assignment to 'submitted' —
46	// these tests each need a fresh assignment so they don't interfere with each other.
47	async function createFreshAssignment(suffix) {
48	  const applicantAcc = await createAccount(`app-${suffix}`);
49	  const [app] = await knex('applications')
50	    .insert({ cycle_id: cycleId, account_id: applicantAcc.id, status: 'submitted' })
51	    .returning('id');
52	  cleanup.applicationIds.push(app.id);
53	
54	  const [a] = await knex('review_assignments')
55	    .insert({
56	      application_id: app.id,
57	      reviewer_id: reviewerProfileId,
58	      cycle_id: cycleId,
59	      assignment_mode: 'manual',
60	      blind_mode: 'blind',
61	      assigned_by: reviewerAccountId,
62	      status: 'assigned',
63	    })
64	    .returning('id');
65	  cleanup.assignmentIds.push(a.id);
66	  return a;
67	}
