186	describe('scoringService.submit — happy path', () => {
187	  it('persists score, transitions assignment to submitted, decrements active_assignments', async () => {
188	    const assignment = await createFreshAssignment('submit-happy');
189	
190	    const score = await scoringService.submit(
191	      {
192	        assignmentId: assignment.id,
193	        criterionScores: { research: 8, statement: 7 },
194	        recommendation: 'admit',
195	      },
196	      reviewerAccountId,
197	      `req-submit-happy-${TS}`,
198	    );
199	
200	    cleanup.reviewScoreIds.push(score.id);
201	
202	    // Score persisted correctly
203	    expect(score.is_draft).toBe(false);
204	    expect(score.recommendation).toBe('admit');
205	    // composite = (8/10*10*60 + 7/10*10*40) / 100 = (48 + 28) / 100 = 7.6
206	    expect(Number(score.composite_score)).toBeCloseTo(7.6, 2);
207	
208	    // Assignment status must be 'submitted'
209	    const updatedAssignment = await knex('review_assignments')
210	      .where({ id: assignment.id })
211	      .first('status');
212	    expect(updatedAssignment.status).toBe('submitted');
213	
214	    // reviewer_profiles.active_assignments must have decremented
215	    const profile = await knex('reviewer_profiles')
216	      .where({ id: reviewerProfileId })
217	      .first('active_assignments');
