222	  it('overwrites a prior draft when submit is called after saveDraft', async () => {
223	    const assignment = await createFreshAssignment('submit-after-draft');
224	
225	    // Save draft first
226	    const draft = await scoringService.saveDraft(
227	      { assignmentId: assignment.id, criterionScores: { research: 5, statement: 5 }, recommendation: 'borderline' },
228	      reviewerAccountId,
229	      `req-draft-before-submit-${TS}`,
230	    );
231	    cleanup.reviewScoreIds.push(draft.id);
232	    expect(draft.is_draft).toBe(true);
233	
234	    // Submit with updated scores — must overwrite the draft row
235	    const submitted = await scoringService.submit(
236	      { assignmentId: assignment.id, criterionScores: { research: 9, statement: 9 }, recommendation: 'strong_admit' },
237	      reviewerAccountId,
238	      `req-submit-over-draft-${TS}`,
239	    );
240	    // Same row — onConflict merge, so id should be identical
241	    expect(submitted.id).toBe(draft.id);
242	    expect(submitted.is_draft).toBe(false);
243	    expect(submitted.recommendation).toBe('strong_admit');
244	
245	    // Only one review_scores row for this assignment
246	    const all = await knex('review_scores').where({ assignment_id: assignment.id });
247	    expect(all).toHaveLength(1);
248	  });
249	});
