9	const RETENTION_DAYS = config.personalization.historyRetentionDays;
10	
11	export const personalizationService = {
12	  // ── View history ───────────────────────────────────────────────────────────
13	
14	  async recordView({ accountId, entityType, stableId, versionId }) {
15	    await knex('entity_view_history').insert({
16	      account_id: accountId,
17	      entity_type: entityType,
18	      stable_id: stableId,
19	      version_id: versionId || null,
20	    });
21	    auditService.record({
22	      actorAccountId: accountId,
23	      actionType: 'personalization.view_recorded',
24	      entityType,
25	      entityId: stableId,
26	      afterSummary: { entityType, versionId: versionId || null },
27	    }).catch((err) => logger.warn({ err }, 'audit write failed'));
28	  },
29	
30	  async getHistory(accountId, options = {}) {
31	    const pageSize = Math.min(options.pageSize || 20, 100);
32	    const page = options.page || 1;
33	    const since = new Date();
34	    since.setDate(since.getDate() - RETENTION_DAYS);
35	    const q = knex('entity_view_history')
36	      .where('account_id', accountId)
37	      .where('viewed_at', '>=', since.toISOString())
38	      .orderBy('viewed_at', 'desc');
39	    if (options.entityType) q.where('entity_type', options.entityType);
40	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
41	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
42	    return { rows, total };
43	  },
44	
45	  // ── Bookmarks ──────────────────────────────────────────────────────────────
46	
47	  async addBookmark({ accountId, entityType, stableId }) {
48	    try {
49	      return await withTransaction(async (trx) => {
50	        const [bookmark] = await trx('entity_bookmarks')
51	          .insert({ account_id: accountId, entity_type: entityType, stable_id: stableId })
52	          .returning('*');
53	        await auditService.record({
54	          actorAccountId: accountId,
55	          actionType: 'personalization.bookmark_added',
56	          entityType,
57	          entityId: stableId,
58	          afterSummary: { entityType },
59	        }, trx);
60	        return bookmark;
61	      });
62	    } catch (err) {
63	      if (err.code === '23505') throw new ConflictError('Already bookmarked');
64	      throw err;
65	    }
66	  },
67	
68	  async removeBookmark({ accountId, entityType, stableId }) {
69	    await withTransaction(async (trx) => {
70	      const deleted = await trx('entity_bookmarks')
71	        .where({ account_id: accountId, entity_type: entityType, stable_id: stableId })
72	        .delete();
73	      if (!deleted) throw new NotFoundError('Bookmark not found');
74	      await auditService.record({
75	        actorAccountId: accountId,
76	        actionType: 'personalization.bookmark_removed',
77	        entityType,
78	        entityId: stableId,
79	        beforeSummary: { entityType },
80	      }, trx);
81	    });
82	  },
83	
84	  async getBookmarks(accountId, options = {}) {
85	    const pageSize = Math.min(options.pageSize || 20, 100);
86	    const page = options.page || 1;
87	    const q = knex('entity_bookmarks').where('account_id', accountId).orderBy('created_at', 'desc');
88	    if (options.entityType) q.where('entity_type', options.entityType);
89	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
90	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
91	    return { rows, total };
92	  },
93	
94	  // ── Preferences ────────────────────────────────────────────────────────────
95	
96	  async getPreferences(accountId) {
97	    const rows = await knex('user_preferences').where('account_id', accountId);
