100	  },
101	
102	  async setPreference(accountId, prefKey, prefValue) {
103	    return withTransaction(async (trx) => {
104	      const [pref] = await trx('user_preferences')
105	        .insert({
106	          account_id: accountId,
107	          pref_key: prefKey,
108	          pref_value: JSON.stringify(prefValue),
