126	    await withTransaction(async (trx) => {
127	      const deleted = await trx('user_preferences')
128	        .where({ account_id: accountId, pref_key: prefKey })
129	        .delete();
130	      if (!deleted) throw new NotFoundError('Preference not found');
131	      await auditService.record({
132	        actorAccountId: accountId,
133	        actionType: 'personalization.preference_deleted',
134	        entityType: 'preference',
135	        entityId: accountId,
136	        beforeSummary: { prefKey },
137	      }, trx);
138	    });
139	  },
140	
141	  // ── Tag subscriptions ──────────────────────────────────────────────────────
142	
143	  async getTagSubscriptions(accountId) {
144	    return knex('tag_subscriptions').where('account_id', accountId).orderBy('created_at', 'desc');
145	  },
146	
147	  async addTagSubscription({ accountId, tag, tagType = 'topic' }) {
148	    try {
149	      return await withTransaction(async (trx) => {
150	        const [sub] = await trx('tag_subscriptions')
151	          .insert({ account_id: accountId, tag, tag_type: tagType })
152	          .returning('*');
153	        await auditService.record({
154	          actorAccountId: accountId,
155	          actionType: 'personalization.tag_subscribed',
156	          entityType: 'tag_subscription',
157	          entityId: accountId,
158	          afterSummary: { tag, tagType },
159	        }, trx);
160	        return sub;
161	      });
162	    } catch (err) {
163	      if (err.code === '23505') throw new ConflictError('Already subscribed to this tag');
164	      throw err;
165	    }
166	  },
167	
168	  async removeTagSubscription({ accountId, tag }) {
169	    await withTransaction(async (trx) => {
170	      const deleted = await trx('tag_subscriptions')
171	        .where({ account_id: accountId, tag })
172	        .delete();
173	      if (!deleted) throw new NotFoundError('Tag subscription not found');
174	      await auditService.record({
175	        actorAccountId: accountId,
176	        actionType: 'personalization.tag_unsubscribed',
177	        entityType: 'tag_subscription',
178	        entityId: accountId,
179	        beforeSummary: { tag },
180	      }, trx);
181	    });
182	  },
183	
184	  // ── Recommendations ────────────────────────────────────────────────────────
185	
186	  /**
187	   * Generate ranked recommendations with a deterministic explanation for each item.
188	   *
189	   * Scoring rules (applied in order, additive):
190	   *   +N   per view in the last 30 days (N = view count)
191	   *   +3   if bookmarked
192	   *   +2   if entity_type matches a tag subscription
193	   *
194	   * Cold-start: when the user has no signals at all, fall back to the 10 most
195	   * recently published active entities across all entity types.
196	   *
197	   * Each recommendation item includes a `reasons` array explaining the score,
198	   * making the output fully explainable.
199	   *
200	   * @param {string} accountId
201	   * @returns {Array<{entityType, stableId, score, reasons}>}
202	   */
203	  async getRecommendations(accountId) {
204	    const since = new Date();
205	    since.setDate(since.getDate() - 30);
206	
207	    recommendationGenerationsTotal.inc();
208	    const [views, bookmarks, tagSubs] = await Promise.all([
209	      knex('entity_view_history')
210	        .where('account_id', accountId)
211	        .where('viewed_at', '>=', since.toISOString())
212	        .select('entity_type', 'stable_id')
213	        .count('id as view_count')
214	        .groupBy('entity_type', 'stable_id')
215	        .orderBy('view_count', 'desc')
216	        .limit(50),
217	      knex('entity_bookmarks')
218	        .where('account_id', accountId)
219	        .select('entity_type', 'stable_id'),
220	      knex('tag_subscriptions')
221	        .where('account_id', accountId)
222	        .select('tag', 'tag_type'),
223	    ]);
224	
225	    const subscribedEntityTypes = new Set(
226	      tagSubs.filter((t) => t.tag_type === 'entity_type').map((t) => t.tag),
227	    );
228	
229	    // ── Cold-start path ───────────────────────────────────────────────────────
230	    if (!views.length && !bookmarks.length && !tagSubs.length) {
231	      const coldRecs = await this._coldStartRecommendations(accountId);
232	      await this._persistExplanations(accountId, coldRecs);
233	      return coldRecs;
234	    }
235	
236	    // ── Scored path ───────────────────────────────────────────────────────────
237	    const topicTags = new Set(
238	      tagSubs.filter((t) => t.tag_type === 'topic').map((t) => t.tag.toLowerCase()),
239	    );
240	
241	    const scoreMap = new Map();
242	
243	    const getOrCreate = (entityType, stableId) => {
244	      const key = `${entityType}:${stableId}`;
245	      if (!scoreMap.has(key)) {
246	        scoreMap.set(key, { entityType, stableId, score: 0, reasons: [] });
247	      }
248	      return scoreMap.get(key);
249	    };
250	
251	    for (const v of views) {
252	      const count = Number(v.view_count);
253	      const item = getOrCreate(v.entity_type, v.stable_id);
254	      item.score += count;
255	      item.reasons.push({ type: 'frequently_viewed', viewCount: count });
256	    }
257	
258	    for (const b of bookmarks) {
259	      const item = getOrCreate(b.entity_type, b.stable_id);
260	      item.score += 3;
261	      item.reasons.push({ type: 'bookmarked' });
262	    }
263	
264	    // Users with only tag subscriptions and no view/bookmark history produce an empty
265	    // scoreMap at this point. Seed it with popular entities from subscribed types so
266	    // the subscription boost below has something to apply to.
267	    if (subscribedEntityTypes.size > 0 && !scoreMap.size) {
268	      const seedItems = await this._coldStartRecommendations(accountId);
269	      for (const item of seedItems) {
270	        getOrCreate(item.entityType, item.stableId);
271	      }
272	    }
273	
274	    // Apply tag-subscription boost to all already-scored items of matching entity type
275	    for (const item of scoreMap.values()) {
276	      if (subscribedEntityTypes.has(item.entityType)) {
277	        item.score += 2;
278	        item.reasons.push({ type: 'tag_subscription', entityType: item.entityType });
279	      }
280	    }
281	
282	    // Apply tag similarity scoring (Jaccard on topic tags vs. entity name tokens)
283	    if (topicTags.size > 0) {
284	      await this._applyTagSimilarity(scoreMap, topicTags);
285	    }
286	
287	    const recommendations = [...scoreMap.values()]
288	      .sort((a, b) => b.score - a.score)
289	      .slice(0, 10);
290	
291	    await this._persistExplanations(accountId, recommendations);
292	    return recommendations;
293	  },
294	
295	  /**
296	   * Compute Jaccard similarity between user's topic tag subscriptions and entity name/tag tokens.
297	   * Applies an additive score boost (max +5) to each matching entity.
298	   *
299	   * @param {Map} scoreMap  The live score map keyed by "entityType:stableId"
300	   * @param {Set<string>} topicTags  Lowercase topic tags from the user's subscriptions
301	   */
302	  async _applyTagSimilarity(scoreMap, topicTags) {
303	    const ENTITY_TABLES = {
304	      university:             { table: 'university_versions',             idCol: 'university_id' },
305	      school:                 { table: 'school_versions',                 idCol: 'school_id' },
306	      major:                  { table: 'major_versions',                  idCol: 'major_id' },
307	      research_track:         { table: 'research_track_versions',         idCol: 'research_track_id' },
308	      enrollment_plan:        { table: 'enrollment_plan_versions',        idCol: 'enrollment_plan_id' },
309	      transfer_quota:         { table: 'transfer_quota_versions',         idCol: 'transfer_quota_id' },
310	      application_requirement: { table: 'application_requirement_versions', idCol: 'application_requirement_id' },
311	      retest_rule:            { table: 'retest_rule_versions',            idCol: 'retest_rule_id' },
312	    };
313	
314	    // Group items by entity type for batched DB fetches
315	    const byType = new Map();
316	    for (const [key, item] of scoreMap) {
317	      if (!byType.has(item.entityType)) byType.set(item.entityType, []);
318	      byType.get(item.entityType).push({ key, stableId: item.stableId });
319	    }
320	
321	    for (const [entityType, items] of byType) {
322	      const cfg = ENTITY_TABLES[entityType];
323	      if (!cfg) continue;
324	      const stableIds = items.map((i) => i.stableId);
325	      const rows = await knex(cfg.table)
326	        .whereIn(cfg.idCol, stableIds)
327	        .where('lifecycle_status', 'active')
328	        .select(
329	          knex.raw(`${cfg.idCol} AS stable_id`),
330	          knex.raw(`payload_json->>'name' AS name`),
331	          knex.raw(`payload_json->>'tags' AS tags`),
332	        );
333	
334	      const entityData = new Map(rows.map((r) => [r.stable_id, r]));
335	      for (const { key, stableId } of items) {
336	        const data = entityData.get(stableId);
337	        if (!data) continue;
338	
339	        // Entity token set = name words + explicit tag array from payload
340	        const nameTokens = (data.name || '').toLowerCase().split(/\s+/).filter(Boolean);
341	        let payloadTags = [];
342	        try { payloadTags = data.tags ? JSON.parse(data.tags) : []; } catch { /* ignore */ }
343	        const entitySet = new Set([...nameTokens, ...payloadTags.map((t) => String(t).toLowerCase())]);
344	
345	        // Jaccard(topicTags, entitySet)
346	        const intersection = [...topicTags].filter((t) => entitySet.has(t)).length;
347	        const union = new Set([...topicTags, ...entitySet]).size;
348	        const similarity = union > 0 ? intersection / union : 0;
349	
350	        if (similarity > 0) {
351	          const item = scoreMap.get(key);
352	          const boost = Math.round(similarity * 5); // max +5 for perfect overlap
353	          item.score += boost;
354	          item.reasons.push({ type: 'tag_similarity', similarity: Math.round(similarity * 100) / 100 });
355	        }
356	      }
357	    }
358	  },
359	
360	  /**
361	   * Persist recommendation explanations for auditability.
362	   * Fire-and-forget (non-blocking) — never surfaces errors to the caller.
363	   */
364	  async _persistExplanations(accountId, recommendations) {
365	    if (!recommendations.length) return;
366	    const now = new Date().toISOString();
367	    const rows = recommendations.map((r) => ({
368	      account_id: accountId,
369	      entity_type: r.entityType,
370	      stable_id: r.stableId,
371	      score: r.score,
372	      reasons: JSON.stringify(r.reasons),
373	      generated_at: now,
374	    }));
375	    knex('recommendation_explanations').insert(rows).catch(() => {});
376	  },
377	
378	  /**
379	   * Cold-start fallback: return up to 10 recommended active entities.
380	   *
381	   * Signal priority:
382	   *   1. Declared interests — entity_type tag subscriptions narrow the candidate pool.
383	   *   2. Popularity         — global view count in the last 30 days ranks candidates.
384	   *   3. Recency            — tie-breaks by published_at DESC.
385	   *
386	   * Used when a user has no view history, bookmarks, or tag subscriptions of their own.
387	   */
388	  async _coldStartRecommendations(accountId) {
389	    const ENTITY_VERSION_TABLES = [
390	      { table: 'university_versions',            entityType: 'university',            idCol: 'university_id' },
391	      { table: 'school_versions',                entityType: 'school',                idCol: 'school_id' },
392	      { table: 'major_versions',                 entityType: 'major',                 idCol: 'major_id' },
393	      { table: 'research_track_versions',        entityType: 'research_track',        idCol: 'research_track_id' },
394	      { table: 'enrollment_plan_versions',       entityType: 'enrollment_plan',       idCol: 'enrollment_plan_id' },
395	      { table: 'transfer_quota_versions',        entityType: 'transfer_quota',        idCol: 'transfer_quota_id' },
396	      { table: 'application_requirement_versions', entityType: 'application_requirement', idCol: 'application_requirement_id' },
397	      { table: 'retest_rule_versions',           entityType: 'retest_rule',           idCol: 'retest_rule_id' },
398	    ];
399	
400	    // Check declared-interest entity_type tag subscriptions
401	    const subscribedTypes = await knex('tag_subscriptions')
402	      .where({ account_id: accountId, tag_type: 'entity_type' })
403	      .pluck('tag');
404	
405	    const targetTables = subscribedTypes.length > 0
406	      ? ENTITY_VERSION_TABLES.filter((e) => subscribedTypes.includes(e.entityType))
407	      : ENTITY_VERSION_TABLES;
408	
409	    const since = new Date();
410	    since.setDate(since.getDate() - 30);
411	
412	    // Global popularity: total view count per entity in the last 30 days
413	    const popularity = await knex('entity_view_history')
414	      .select('entity_type', 'stable_id')
415	      .count('id as view_count')
416	      .where('viewed_at', '>=', since.toISOString())
417	      .groupBy('entity_type', 'stable_id');
418	
419	    const popularityMap = new Map(
420	      popularity.map((r) => [`${r.entity_type}:${r.stable_id}`, Number(r.view_count)]),
421	    );
422	
423	    const parts = await Promise.all(
424	      targetTables.map(({ table, entityType, idCol }) =>
425	        knex(table)
426	          .where('lifecycle_status', 'active')
427	          .orderBy('published_at', 'desc')
428	          .limit(20)
429	          .select(knex.raw(`'${entityType}' AS entity_type`), `${idCol} AS stable_id`, 'published_at'),
430	      ),
431	    );
432	
433	    const basis = subscribedTypes.length > 0 ? 'declared_interest' : 'recently_popular';
434	
435	    return parts
436	      .flat()
437	      .map((r) => ({
438	        entityType: r.entity_type,
439	        stableId: r.stable_id,
440	        publishedAt: r.published_at,
441	        popularity: popularityMap.get(`${r.entity_type}:${r.stable_id}`) || 0,
442	      }))
443	      .sort((a, b) => b.popularity - a.popularity || new Date(b.publishedAt) - new Date(a.publishedAt))
444	      .slice(0, 10)
445	      .map((r) => ({
446	        entityType: r.entityType,
447	        stableId: r.stableId,
448	        score: 0,
449	        reasons: [{ type: 'cold_start', basis }],
450	      }));
451	  },
452	};
