1	import { withTransaction } from '../../common/db/transaction.js';
2	import { NotFoundError, ConflictError, AuthorizationError } from '../../common/errors/AppError.js';
3	import { searchService } from './search.service.js';
4	import { auditService } from '../admin/audit/audit.service.js';
5	import knex from '../../common/db/knex.js';
6	
7	export const savedQueriesService = {
8	  async list(accountId, options = {}) {
9	    const page = Number(options.page) || 1;
10	    const pageSize = Math.min(Number(options.pageSize) || 20, 100);
11	    const q = knex('search_saved_queries')
12	      .where({ account_id: accountId })
13	      .orderBy('updated_at', 'desc');
14	    if (options.subscribed != null) q.where('subscribed', options.subscribed === 'true');
15	    const total = await q.clone().count('id as count').first().then((r) => Number(r.count));
16	    const rows = await q.limit(pageSize).offset((page - 1) * pageSize);
17	    return { rows, total };
18	  },
19	
20	  async create({ accountId, name, queryText, filters = {}, subscribed = false }) {
21	    try {
22	      return await withTransaction(async (trx) => {
23	        const [sq] = await trx('search_saved_queries')
24	          .insert({ account_id: accountId, name, query_text: queryText, filters: JSON.stringify(filters), subscribed })
25	          .returning('*');
26	        await auditService.record({
27	          actorAccountId: accountId,
28	          actionType: 'saved_query.created',
29	          entityType: 'saved_query',
30	          entityId: String(sq.id),
31	          afterSummary: { name },
32	        }, trx);
33	        return sq;
34	      });
35	    } catch (err) {
36	      if (err.code === '23505') throw new ConflictError('A saved query with this name already exists');
37	      throw err;
38	    }
39	  },
40	
41	  async update(id, accountId, patch) {
42	    return withTransaction(async (trx) => {
43	      const sq = await trx('search_saved_queries').where({ id }).first();
44	      if (!sq) throw new NotFoundError('Saved query not found');
45	      if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
46	
47	      const update = { updated_at: new Date().toISOString() };
48	      // Accept both camelCase API contract field (queryText) and snake_case DB column
49	      if (patch.name != null) update.name = patch.name;
50	      if (patch.queryText != null) update.query_text = patch.queryText;
51	      if (patch.filters != null) update.filters = JSON.stringify(patch.filters);
52	      if (patch.subscribed != null) update.subscribed = patch.subscribed;
53	
54	      const [updated] = await trx('search_saved_queries').where({ id }).update(update).returning('*');
55	      await auditService.record({
56	        actorAccountId: accountId,
57	        actionType: 'saved_query.updated',
58	        entityType: 'saved_query',
59	        entityId: String(id),
60	        beforeSummary: { name: sq.name },
61	        afterSummary: { name: updated.name },
62	      }, trx);
63	      return updated;
64	    });
65	  },
66	
67	  async delete(id, accountId) {
68	    await withTransaction(async (trx) => {
69	      const sq = await trx('search_saved_queries').where({ id }).first();
70	      if (!sq) throw new NotFoundError('Saved query not found');
71	      if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
72	      await trx('search_saved_queries').where({ id }).delete();
73	      await auditService.record({
74	        actorAccountId: accountId,
75	        actionType: 'saved_query.deleted',
76	        entityType: 'saved_query',
77	        entityId: String(id),
78	        beforeSummary: { name: sq.name },
79	      }, trx);
80	    });
81	  },
82	
83	  /**
84	   * Run a saved query and update last_run_at + last_result_count.
85	   */
86	  async run(id, accountId) {
87	    const sq = await knex('search_saved_queries').where({ id }).first();
88	    if (!sq) throw new NotFoundError('Saved query not found');
89	    if (sq.account_id !== accountId) throw new AuthorizationError('Access denied');
90	
91	    const result = await searchService.search(sq.query_text, {
92	      entityTypes: sq.filters?.entityTypes,
93	      lifecycleStatus: sq.filters?.lifecycleStatus,
94	      effectiveFrom: sq.filters?.effectiveFrom,
95	      effectiveTo: sq.filters?.effectiveTo,
96	      nameContains: sq.filters?.nameContains,
97	      descriptionContains: sq.filters?.descriptionContains,
98	      tags: sq.filters?.tags,
99	      accountId,
100	    });
101	
102	    await knex('search_saved_queries').where({ id }).update({
103	      last_run_at: new Date().toISOString(),
104	      last_result_count: result.total,
105	      updated_at: new Date().toISOString(),
106	    });
107	
108	    return result;
109	  },
