127	     *   - Future effective date → new version becomes 'scheduled'
128	     */
129	    async publishVersion(stableId, versionId, actorId, trx, effectiveFrom) {
130	      const db = trx || knex;
131	
132	      const version = await db(versionsTable)
133	        .where({ id: versionId, [stableIdColumn]: stableId })
