15	import knex from '../src/common/db/knex.js';
16	import { makeVersionedRepository } from '../src/modules/university-data/_versioning/versioned-repository.factory.js';
17	
18	const ENTITY_CONFIGS = [
19	  { stableTable: 'universities',              versionsTable: 'university_versions',               stableIdColumn: 'university_id' },
20	  { stableTable: 'schools',                   versionsTable: 'school_versions',                   stableIdColumn: 'school_id' },
21	  { stableTable: 'majors',                    versionsTable: 'major_versions',                    stableIdColumn: 'major_id' },
22	  { stableTable: 'research_tracks',           versionsTable: 'research_track_versions',           stableIdColumn: 'research_track_id' },
23	  { stableTable: 'enrollment_plans',          versionsTable: 'enrollment_plan_versions',          stableIdColumn: 'enrollment_plan_id' },
24	  { stableTable: 'transfer_quotas',           versionsTable: 'transfer_quota_versions',           stableIdColumn: 'transfer_quota_id' },
25	  { stableTable: 'application_requirements', versionsTable: 'application_requirement_versions',  stableIdColumn: 'application_requirement_id' },
26	  { stableTable: 'retest_rules',             versionsTable: 'retest_rule_versions',              stableIdColumn: 'retest_rule_id' },
27	];
28	
29	async function run() {
30	  const today = new Date().toISOString().split('T')[0];
31	  let totalPromoted = 0;
32	
33	  for (const cfg of ENTITY_CONFIGS) {
34	    const repo = makeVersionedRepository(cfg);
35	
36	    // Find all stable IDs that have at least one due scheduled version
37	    const dueEntities = await knex(cfg.versionsTable)
38	      .where({ lifecycle_status: 'scheduled' })
39	      .where('effective_from', '<=', today)
40	      .distinct(cfg.stableIdColumn)
41	      .pluck(cfg.stableIdColumn);
42	
43	    for (const stableId of dueEntities) {
44	      const promoted = await repo.promoteScheduled(stableId, null, knex);
45	      if (promoted) {
46	        console.log(`[promote] ${cfg.stableTable} ${stableId} → v${promoted.version_number} active (effective ${promoted.effective_from})`);
